-- Poems batch 55
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('b104cf65-4ad6-4010-a19d-395125b685ee','又嘲屏牆','裴略','唐','唐诗','tang','','[]','高下八九尺，東西六七步。',24,'全唐诗/poet.tang.48000.json','["高下八九尺，東西六七步。", "突兀當廳坐，幾許遮賢路。"]'),
('59b057b4-f271-488a-b3f7-70a07ca537d0','嘲崔左丞','省吏','唐','唐诗','tang','','[]','崔子曲如鉤，隨例得封侯。',24,'全唐诗/poet.tang.48000.json','["崔子曲如鉤，隨例得封侯。", "髆上全無項，胸前別有頭。"]'),
('5c73fe42-22f2-4348-9e02-69b511867818','嘲高士廉木履','選人','唐','唐诗','tang','','[]','刺鼻何曾嚏，蹋面不知嗔。',24,'全唐诗/poet.tang.48000.json','["刺鼻何曾嚏，蹋面不知嗔。", "高生兩箇齒，自謂得勝人。"]'),
('01347646-dd39-47d2-8870-2fc1a11fc74c','書化度藏院壁','裴玄智','唐','唐诗','tang','','[]','將肉遣狼守，置骨向狗頭。',24,'全唐诗/poet.tang.48000.json','["將肉遣狼守，置骨向狗頭。", "自非阿羅漢，焉能免得偷。"]'),
('fae5cb13-5506-411c-a957-f3eee4b0f57d','嘲許子儒','竇昉','唐','唐诗','tang','','[]','不能專習禮，虛心強覓階。',72,'全唐诗/poet.tang.48000.json','["不能專習禮，虛心強覓階。", "一年辭爵弁，半歲履麻鞋。", "瓦惡頻蒙𢸗，墻虛屢被扠。", "映樹便側睡，過匱即放乖。", "歲暮良工畢，言是越朋儕。", "今日綸言降，方知愚計喎。"]'),
('104fd722-b3f4-4240-8b82-71b8e3f6fc49','與趙神德互嘲','梁寶','唐','唐诗','tang','','[]','趙神德，天上既無雲，閃電何以無準則。',56,'全唐诗/poet.tang.48000.json','["趙神德，天上既無雲，閃電何以無準則。", "向者入門來，案後惟見一挺墨。", "官裏料朱砂，半眼供一國。", "磨公小拇指，塗得太社北。"]'),
('ffe8b26f-8d79-466d-973c-9d8269e8e425','與講師互謔','釋元康','唐','唐诗','tang','','[]','甘桃不結實，苦李壓低枝。',24,'全唐诗/poet.tang.48000.json','["甘桃不結實，苦李壓低枝。", "輪王千箇子，巷伯勿孫兒。"]'),
('463f6093-4493-495e-99cc-f2c034c8c874','詠興善寺佛殿災','李榮','唐','唐诗','tang','','[]','道善何曾善，言興且不興。',24,'全唐诗/poet.tang.48000.json','["道善何曾善，言興且不興。", "如來燒赤盡，惟有一羣僧。"]'),
('8d51deb0-399b-4ee2-8288-56f650ee7e9b','敘可笑事','張元一','唐','唐诗','tang','','[]','朱前疑著綠，逯仁傑著朱。',52,'全唐诗/poet.tang.48000.json','["朱前疑著綠，逯仁傑著朱。", "閻知微騎馬，馬吉甫騎驢。", "將名作姓李千里，將姓作名吳栖梧。", "左臺胡御史，右臺御史胡。"]'),
('b105b34b-bfa9-4d35-b307-f5e90a3d7740','嘲武懿宗','張元一','唐','唐诗','tang','','[]','長弓短度箭，蜀馬臨階騗。',36,'全唐诗/poet.tang.48000.json','["長弓短度箭，蜀馬臨階騗。", "去賊七百里，隈墻獨自戰。", "忽然逢著賊，騎豬向南𧾩。"]'),
('42fa29ca-dafd-4616-90f0-da2f1b802955','又嘲武懿宗','張元一','唐','唐诗','tang','','[]','裹頭極草草，掠鬢不菶菶。',26,'全唐诗/poet.tang.48000.json','["裹頭極草草，掠鬢不菶菶。", "未見桃花面皮，漫作杏子眼孔。"]'),
('278596d5-b47a-4379-9429-2b98a732ad40','詠靜樂縣主','張元一','唐','唐诗','tang','','[]','馬帶桃花錦，帬銜綠草羅。',24,'全唐诗/poet.tang.48000.json','["馬帶桃花錦，帬銜綠草羅。", "定知幃帽底，儀容似大哥。"]'),
('232e79ed-ed88-4110-a038-fc2dd71a5df2','嘲格輔元','杜易簡','唐','唐诗','tang','','[]','有恥宿龍門，精彩先瞰渾。',48,'全唐诗/poet.tang.48000.json','["有恥宿龍門，精彩先瞰渾。", "眼瘦呈近店，睡響徹遙林。", "埒囊將舊識，製被異新婚。", "誰言驄馬使，飜作蟄熊蹲。"]'),
('71c1a098-46fb-485f-9d19-d47361bef04b','始平諧詩','石抱忠','唐','唐诗','tang','','[]','平明發始平，薄暮至何城。',56,'全唐诗/poet.tang.48000.json','["平明發始平，薄暮至何城。", "庫墖朝雲上，晃池夜月明。", "略彴橋頭逢長史，櫺星門外揖司兵。", "一羣縣尉驢騾驟，數箇參軍鵝鴨行。"]'),
('c790ecf1-5730-493d-920f-fbc5a7b5b009','詠傅巖監祠','梁載言','唐','唐诗','tang','','[]','聞道監中霤，初言是大祠。',48,'全唐诗/poet.tang.48000.json','["聞道監中霤，初言是大祠。", "很傍索傳馬，𬾠動出安徽。", "衛司無帟幕，供膳乏鮮肥。", "形容消瘦盡，空往復空歸。"]'),
('61728213-0a86-4629-978c-bc36e755ba36','嘲崔生','劉行敏','唐','唐诗','tang','','[]','崔生犯夜行，武候正嚴更。',48,'全唐诗/poet.tang.48000.json','["崔生犯夜行，武候正嚴更。", "幞頭拳下落，高髻掌中擎。", "杖迹胸前出，繩文腕後生。", "愁人不惜夜，隨意曉參橫。"]'),
('2eefd72c-00fc-40aa-a3da-2e9c53e5eb00','又嘲楊文瓘','劉行敏','唐','唐诗','tang','','[]','武陵敬愛客，終宴不知疲。',48,'全唐诗/poet.tang.48000.json','["武陵敬愛客，終宴不知疲。", "遣共渾王飲，錯宴延陀兒。", "始被鴻臚識，終蒙御史知。", "精神既如此，長歎復何爲。"]'),
('a87ae15a-f618-4585-96c3-a23eff99e74d','嘲李叔慎賀蘭僧伽杜善賢','劉行敏','唐','唐诗','tang','','[]','叔慎騎烏馬，僧伽把漆弓。',24,'全唐诗/poet.tang.48000.json','["叔慎騎烏馬，僧伽把漆弓。", "喚取長安令，共獵北山熊。"]'),
('c8ab327a-94f5-4cd2-ac5c-118ce26089d1','嘲父','陸子','唐','唐诗','tang','','[]','陸餘慶，筆頭無力觜頭硬。',24,'全唐诗/poet.tang.48000.json','["陸餘慶，筆頭無力觜頭硬。", "一朝受辭訟，十日判不竟。"]'),
('8b26a219-0097-4fd7-9a3a-3ac3512e4582','迴波詞','楊廷玉','唐','唐诗','tang','','[]','迴波爾時廷玉，打獠取錢未足。',29,'全唐诗/poet.tang.48000.json','["迴波爾時廷玉，打獠取錢未足。", "阿姑婆見作天子，傍人不得棖觸。"]'),
('e15865c3-e43c-41d7-bc4e-7d625f37960a','迴波詞','中宗朝優人','唐','唐诗','tang','','[]','迴波爾時栲栳，怕婦也是大好。',28,'全唐诗/poet.tang.48000.json','["迴波爾時栲栳，怕婦也是大好。", "外邊祗有裴談，內里無過李老。"]'),
('6fe30e4c-25d1-437a-ade1-bc97d0add9e3','乞金魚詞','崔日用','唐','唐诗','tang','','[]','臺中鼠子直須諳，信足跳梁上壁龕。',56,'全唐诗/poet.tang.48000.json','["臺中鼠子直須諳，信足跳梁上壁龕。", "倚飜燈脂汚張五，還來齧帶報韓三。", "莫浪語，直王相，大家必若賜金龜，賣却貓兒相報賞。"]'),
('c5d0b985-9e6a-4799-8a28-63623f119228','又賜宴自歌','崔日用','唐','唐诗','tang','','[]','東館總是鵷鸞，南臺自多杞梓。',42,'全唐诗/poet.tang.48000.json','["東館總是鵷鸞，南臺自多杞梓。", "日用讀書萬卷，何忍不蒙學士。", "墨制簾下出來，微臣眼看喜死。"]'),
('f51d8b7b-116e-42fb-88f3-d68b1888b378','詠癡','吳人','唐','唐诗','tang','','[]','榆兒復榆婦，造屋兼造車。',24,'全唐诗/poet.tang.48000.json','["榆兒復榆婦，造屋兼造車。", "十七八九夜，還書復借書。"]'),
('7d4caf45-52b5-4a97-bbb0-8fd7900fcb2b','歇後','封抱一','唐','唐诗','tang','','[]','面作天地玄，鼻有雁門紫。',24,'全唐诗/poet.tang.48000.json','["面作天地玄，鼻有雁門紫。", "既無左達承，何勞罔談彼。"]'),
('477ea2b0-981b-482c-986d-d4b4ed725539','送司功入京','麴崇裕','唐','唐诗','tang','','[]','崇裕有幸會，得遇明流行。',24,'全唐诗/poet.tang.48000.json','["崇裕有幸會，得遇明流行。", "司士向京去，曠野哭聲哀。"]'),
('fcb52ce7-3cde-4b77-bdf8-ec58a5aebd1c','嶺南歸後獻詩','權龍褒','唐','唐诗','tang','','[]','龍褒有何罪，天恩放嶺南。',24,'全唐诗/poet.tang.48000.json','["龍褒有何罪，天恩放嶺南。", "敕知無罪過，追來與將軍。"]'),
('30543d11-40a3-473d-8c9c-004e05d05bc6','初到滄州呈州官','權龍褒','唐','唐诗','tang','','[]','遙看滄海城，楊柳鬱青青。',24,'全唐诗/poet.tang.48000.json','["遙看滄海城，楊柳鬱青青。", "中央一羣漢，聚坐打杯觥。"]'),
('d5cb87ff-7aa7-4095-8274-ad6c9993b73c','秋日述懷','權龍褒','唐','唐诗','tang','','[]','檐前飛七百，雪白後園彊。',24,'全唐诗/poet.tang.48000.json','["檐前飛七百，雪白後園彊。", "飽食房裏側，家糞集野蜋。"]'),
('00626b70-9005-4cf7-9e75-30972b6e1877','喜雨','權龍褒','唐','唐诗','tang','','[]','暗去也沒雨，明來也沒雲。',24,'全唐诗/poet.tang.48000.json','["暗去也沒雨，明來也沒雲。", "日頭赫赤出，地上綠氤氳。"]'),
('ca065bd5-de7e-4b4a-8b65-53b5b973e6ac','皇太子夏日賜宴詩','權龍褒','唐','唐诗','tang','','[]','嚴霜白浩浩，明月赤團團。',12,'全唐诗/poet.tang.48000.json','["嚴霜白浩浩，明月赤團團。"]'),
('77ee1a89-aed7-49e6-9b72-7cf6d6259780','哭李嶠詩','崔泰之','唐','唐诗','tang','','[]','臺閣神仙地，衣冠君子鄉。',48,'全唐诗/poet.tang.48000.json','["臺閣神仙地，衣冠君子鄉。", "昨朝猶對坐，今日忽云亡。", "魂隨司命鬼，魄逐見閻王。", "此時罷歡笑，無復向朝堂。"]'),
('0a0848bc-da0e-4623-9dd0-0a6995e3feae','詠尹字','蘇頲','唐','唐诗','tang','','[]','丑雖有足，甲不全身。',20,'全唐诗/poet.tang.48000.json','["丑雖有足，甲不全身。", "見君無口，知伊少人。"]'),
('4436e5bd-a636-474f-b081-c188212be626','詠王主敬','張敬忠','唐','唐诗','tang','','[]','有意嫌兵部，專心望考功。',24,'全唐诗/poet.tang.48000.json','["有意嫌兵部，專心望考功。", "誰知脚踜蹬，却落省牆東。"]'),
('9a172985-54b3-4388-953b-60ea0e16b42f','嘲邵景蕭嵩','韋鏗','唐','唐诗','tang','','[]','一雙胡子著緋袍，一箇鬚多一鼻高。',32,'全唐诗/poet.tang.48000.json','["一雙胡子著緋袍，一箇鬚多一鼻高。", "相對廳前捺且立，自慙身品世間毛。"]'),
('1ae6672e-58e1-4c66-8e4d-91ba617c36bc','嘲韋鏗','邵景','唐','唐诗','tang','','[]','飄風忽起團團旋，倒地還如著脚䭔。',32,'全唐诗/poet.tang.48000.json','["飄風忽起團團旋，倒地還如著脚䭔。", "莫怪殿上空行事，却爲元非五品才。"]'),
('ac792b8c-adeb-4bde-9f9a-f962cfd54255','詠毀天樞','李休烈','唐','唐诗','tang','','[]','天門街上倒天樞，火急先須卸火珠。',32,'全唐诗/poet.tang.48000.json','["天門街上倒天樞，火急先須卸火珠。", "計合一條麻線挽，何勞兩縣索人夫。"]'),
('2ec2a3cc-702b-4015-a9f9-ff0fbae6f7af','與李全交詩','石惠泰','唐','唐诗','tang','','[]','御史非常任，參軍不久居。',24,'全唐诗/poet.tang.48000.json','["御史非常任，參軍不久居。", "待君遷轉後，此職還到余。"]'),
('94685790-d054-4585-b093-645d7141beaa','嘲劉文樹','黃幡綽','唐','唐诗','tang','','[]','可憐好箇劉文樹，髭鬚共頦頤別住。',34,'全唐诗/poet.tang.48000.json','["可憐好箇劉文樹，髭鬚共頦頤別住。", "文樹面孔不似猢猻，猢猻面孔強似文樹。"]'),
('b631320e-73fc-43f7-8d4d-3f9ac668d155','尚書省門吟','祖詠','唐','唐诗','tang','','[]','落去他，兩兩三三戴帽子。',28,'全唐诗/poet.tang.48000.json','["落去他，兩兩三三戴帽子。", "日暮祖侯吟一聲，長安竹柏皆枯死。"]'),
('706a6715-b027-4a1e-acd6-3cc910974dd7','上馬當山神','王昌齡','唐','唐诗','tang','','[]','青驄一匹崑崙牽，奏上大王不取錢。',32,'全唐诗/poet.tang.48000.json','["青驄一匹崑崙牽，奏上大王不取錢。", "直爲猛風波滾驟，莫怪昌齡不下船。"]'),
('84e07753-e67b-46d4-99d1-02e7b43341ca','竊李義府詩','張懷慶','唐','唐诗','tang','','[]','生情鏤月爲歌扇，出性裁雲作舞衣。',32,'全唐诗/poet.tang.48000.json','["生情鏤月爲歌扇，出性裁雲作舞衣。", "照鏡自憐迴雪影，來時好取洛川歸。"]'),
('4fec622e-42ba-4f8e-951f-b6c3c1e89b91','荅朝士','賀知章','唐','唐诗','tang','','[]','鈒鏤銀盤盛蛤蜊，鏡湖蓴菜亂如絲。',32,'全唐诗/poet.tang.48000.json','["鈒鏤銀盤盛蛤蜊，鏡湖蓴菜亂如絲。", "鄉曲近來佳此味，遮渠不道是吳兒。"]'),
('b8568c12-f9f1-4a46-8ba2-01b7efecd580','和知章詩','顧況','唐','唐诗','tang','','[]','鈒鏤銀盤盛炒鰕，鏡湖蓴菜亂如麻。',32,'全唐诗/poet.tang.48000.json','["鈒鏤銀盤盛炒鰕，鏡湖蓴菜亂如麻。", "漢兒女嫁吳兒婦，吳兒盡是漢兒爺。"]'),
('ef209680-bd61-4f71-84b2-64994e2e20a4','續茅山秀才吟','顧況','唐','唐诗','tang','','[]','駐馬上山阿，風來屎氣多。',12,'全唐诗/poet.tang.48000.json','["駐馬上山阿，風來屎氣多。"]'),
('3e1edd84-b808-4f24-b79e-51f4d28987f1','櫻桃子詩','史思明','唐','唐诗','tang','','[]','櫻桃子，半赤半已黃。',22,'全唐诗/poet.tang.48000.json','["櫻桃子，半赤半已黃。", "一半與懷王，一半與周至。"]'),
('e45731a3-8d0b-4a18-8fb0-c1cf57807d2c','譏元載詩','高亭','唐','唐诗','tang','','[]','上元官吏務剝削，江淮之人皆白著。',16,'全唐诗/poet.tang.48000.json','["上元官吏務剝削，江淮之人皆白著。"]'),
('72cb7f32-233f-4647-af45-3fce77dd380e','嘲趙謙光','賀遂涉','唐','唐诗','tang','','[]','員外由來美，郎中望亦優。',24,'全唐诗/poet.tang.48000.json','["員外由來美，郎中望亦優。", "寧知粉署裏，飜作土山頭。"]'),
('e3546170-8ec5-420c-a9b6-432ce63eb74e','荅賀遂涉','趙謙光','唐','唐诗','tang','','[]','錦帳隨情設，金爐任意熏。',24,'全唐诗/poet.tang.48000.json','["錦帳隨情設，金爐任意熏。", "唯愁員外置，不應列星文。"]'),
