('9ea50bdb-5aa9-46a1-b1cd-808496a92fa1','射覆巾子','不詳','唐','唐诗','tang','','[]','近來好裹束，各自競尖新。',24,'全唐诗/poet.tang.48000.json','["近來好裹束，各自競尖新。", "秤無三五兩，因何號一斤。"]'),
('eeffbc2c-5b22-49c8-9685-bee2177ca516','射覆二雞子','不詳','唐','唐诗','tang','','[]','此物不難知，一雄兼一雌。',24,'全唐诗/poet.tang.48000.json','["此物不難知，一雄兼一雌。", "誰將打破看，方明混沌時。"]'),
('ab67b350-f74a-40e6-bd7f-332e04ce1bbb','天衝星占','不詳','唐','唐诗','tang','','[]','天衝抱極泣帝前，血濁霧下天下冤。',16,'全唐诗/poet.tang.48000.json','["天衝抱極泣帝前，血濁霧下天下冤。"]'),
('6bb7f041-7d79-464d-9dfa-ba76699c4b79','占月語','不詳','唐','唐诗','tang','','[]','月如彎弓，少雨多風。',20,'全唐诗/poet.tang.48000.json','["月如彎弓，少雨多風。", "月如仰瓦，不求自下。"]'),
('feefdf82-bc7e-4133-95b2-2e00528bf483','占雨 一','不詳','唐','唐诗','tang','','[]','乾星照溼土，明日依舊雨。',12,'全唐诗/poet.tang.48000.json','["乾星照溼土，明日依舊雨。"]'),
('8b5bea73-b730-45e1-9df3-6e242fd3d2b6','占雨 二','不詳','唐','唐诗','tang','','[]','雲行西，星照泥。',8,'全唐诗/poet.tang.48000.json','["雲行西，星照泥。"]'),
('0db4d9c5-b2e0-4af0-a719-7868b5f1de07','占雨 三','不詳','唐','唐诗','tang','','[]','朝霞不出門，暮霞行千里。',12,'全唐诗/poet.tang.48000.json','["朝霞不出門，暮霞行千里。"]'),
('88034b80-42bc-4a54-992e-69f308e138a5','占雨 四','不詳','唐','唐诗','tang','','[]','天將雨，鳩逐婦。',8,'全唐诗/poet.tang.48000.json','["天將雨，鳩逐婦。"]'),
('0a605fe4-6622-42c1-9726-4eafde7a4880','占四時甲子雨','不詳','唐','唐诗','tang','','[]','春雨甲子，赤地千里。',50,'全唐诗/poet.tang.48000.json','["春雨甲子，赤地千里。", "夏雨甲子，乘船入市。", "秋雨甲子，禾頭生耳。", "冬雨甲子，牛羊凍死。", "鵲巢下地，其年大水。"]'),
('fb02add6-9d4d-4bf6-8a7f-cc2f9fb8498f','占年 一','不詳','唐','唐诗','tang','','[]','要見麥，見三白。',8,'全唐诗/poet.tang.48000.json','["要見麥，見三白。"]'),
('4095cac5-b133-46bf-8b0a-8b3e1773aa7b','占年 二','不詳','唐','唐诗','tang','','[]','正月三白，田公笑赫赫。',11,'全唐诗/poet.tang.48000.json','["正月三白，田公笑赫赫。"]'),
('434e0cf7-dc7d-49c8-bbd1-a1a59a461436','樹稼諺','不詳','唐','唐诗','tang','','[]','樹稼，達官怕。',7,'全唐诗/poet.tang.48000.json','["樹稼，達官怕。"]'),
('b2559017-abc2-4518-9d07-356c0629d03e','相書語','不詳','唐','唐诗','tang','','[]','目有四白，五夫守宅。',10,'全唐诗/poet.tang.48000.json','["目有四白，五夫守宅。"]'),
('6c7c2d90-028a-42bb-b073-e5d7f041dc86','葬書語 一','不詳','唐','唐诗','tang','','[]','葬壓龍角，其棺必斲。',10,'全唐诗/poet.tang.48000.json','["葬壓龍角，其棺必斲。"]'),
('50cfb8f4-ec53-42c0-adf7-43d903d36951','葬書語 二','不詳','唐','唐诗','tang','','[]','朱雀和鳴，子孫盛榮。',10,'全唐诗/poet.tang.48000.json','["朱雀和鳴，子孫盛榮。"]'),
('2bcf8b1b-926c-44d5-9263-ede855349932','葬書語 三','不詳','唐','唐诗','tang','','[]','朱雀悲哀，棺中見灰。',10,'全唐诗/poet.tang.48000.json','["朱雀悲哀，棺中見灰。"]'),
('b8ea55ea-5039-4860-8601-8fa310a954d6','葬書語 四','不詳','唐','唐诗','tang','','[]','安龍頭，枕龍角。',16,'全唐诗/poet.tang.48000.json','["安龍頭，枕龍角。", "不三年，自消鑠。"]'),
('3aade48b-4bbc-47b0-9dc0-d12f728e68f3','葬書語 五','不詳','唐','唐诗','tang','','[]','安龍頭，枕龍耳。',16,'全唐诗/poet.tang.48000.json','["安龍頭，枕龍耳。", "不三年，萬乘至。"]'),
('2f89c9ab-8012-4e13-adac-82ef9b948047','陰陽書語','不詳','唐','唐诗','tang','','[]','喬木先枯，衆子必孤。',10,'全唐诗/poet.tang.48000.json','["喬木先枯，衆子必孤。"]'),
('dd6fb19e-48f4-4fb4-9792-c000cf019bcf','本草采萍時日歌','不詳','唐','唐诗','tang','','[]','不在山，不在岸，采我之時七月半。',48,'全唐诗/poet.tang.48000.json','["不在山，不在岸，采我之時七月半。", "選甚癱風與緩風，些小微風都不算。", "豆淋酒內下三丸，鐵幞頭上也出汗。"]'),
('dfaf74b9-357e-46f3-87bf-37d4e6898606','和劑方補骨脂丸方詩','不詳','唐','唐诗','tang','','[]','三年時節向邊隅，人信方知藥力殊。',32,'全唐诗/poet.tang.48000.json','["三年時節向邊隅，人信方知藥力殊。", "奪得春光來在手，青娥休笑白髭鬚。"]'),
('6e0061bb-87a7-4efe-8bfa-953dc663d6c4','李廷珪藏墨訣','不詳','唐','唐诗','tang','','[]','贈爾烏玉玦，泉清硏須潔。',24,'全唐诗/poet.tang.48000.json','["贈爾烏玉玦，泉清硏須潔。", "避暑懸葛囊，臨風度梅月。"]'),
('f8a6a251-3d49-494b-8fca-f903e14da232','蒙求','李瀚','唐','唐诗','tang','','[]','王戎簡要，裴楷清通。',240,'全唐诗/poet.tang.48000.json','["王戎簡要，裴楷清通。", "孔明臥龍，呂望非熊。", "楊震關西，丁寬易東。", "謝安高潔，王導公忠。", "匡衡鑿壁，孫敬閉戶。", "郅都蒼鷹，寧成乳虎。", "周嵩狼抗，梁冀跋扈。", "郗超䫇參，王珣短簿。", "伏波標柱，博望尋河。", "李陵初詩，田橫感歌。", "武仲不休，士衡患多。", "桓譚非讖，王商止訛。", "嵇呂命駕，程孔傾蓋。", "劇孟一敵，周處三害。", "胡廣補闕，袁安倚賴。", "黃霸政殊，梁習治最。", "墨子悲絲，楊朱泣岐。", "朱博烏集，蕭芝雉隨。", "杜后生齒，靈王出髭。", "賈誼忌鵩，莊周畏犧。", "燕昭築臺，鄭莊置驛。", "瓘靖二妙，岳湛連璧。", "郄詵一枝，戴馮重席。", "鄒陽長裾，王符逢掖。"]'),
('ebabe85e-144e-4661-a853-09bbb5005868','宗廟九德之歌辭','褚亮','唐','唐诗','tang','','[]','皇祖誕慶，於昭于天。',80,'全唐诗/poet.tang.48000.json','["皇祖誕慶，於昭于天。", "積德斯遠，茂攸緒先。", "維文應曆，神武弘宣。", "肇迹□水，成功坂泉。", "道光覆載，聲穆吉先。", "式備犧象，用□牲牷。", "禮終九獻，樂展四懸。", "神貺景福，遐哉永年。"]'),
('e9695ecc-7555-4829-b1e8-5699038ccc78','太廟祼地歌辭','陳叔達','唐','唐诗','tang','','[]','清廟既裸，鬱鬯推禮。',60,'全唐诗/poet.tang.48000.json','["清廟既裸，鬱鬯推禮。", "大哉孝思，嚴恭祖禰。", "龍衮以祭，鸞刀思啓。", "發德朱弦，升歌丹陛。", "遙享粢盛，堂斟況齊。", "降福穰穰，來儀濟濟。"]'),
('7684ea4c-fd62-456e-aed3-5a90d9a71089','堦前石行','王績','唐','唐诗','tang','','["\u548f\u7269\u8bd7", "\u7af9\u5b50", "\u548f\u7269"]','上天布甘雨，萬物咸均平。',84,'全唐诗/poet.tang.48000.json','["上天布甘雨，萬物咸均平。", "自顧微且賤，亦得蒙滋榮。", "萋萋結綠枝，曄曄垂朱英。", "常恐零露降，不得全其生。", "歎息聊自思，此生豈我情。", "昔我未生時，誰者令我萌。", "棄置勿重陳，委化何所營。"]'),
('37de5d02-7e31-47d9-8e5a-9aa80bccdc62','九月九日','崔善爲','唐','唐诗','tang','','[]','九日重陽節，三秋季月殘。',48,'全唐诗/poet.tang.48000.json','["九日重陽節，三秋季月殘。", "菊花催晚氣，萸房辟早寒。", "霜濃鷹擊遠，霧重雁飛難。", "誰憶龍山外，蕭條邊興闌。"]'),
('9f7168e7-dda7-4db8-a257-a9bbbff8883b','奉和九月九日應制','許敬宗','唐','唐诗','tang','','["\u9ec4\u5c71"]','爽氣申時豫，臨秋肆武功。',108,'全唐诗/poet.tang.48000.json','["爽氣申時豫，臨秋肆武功。", "太液榮光發，曾城佳氣融。", "紫霄寒暑麗，黃山極望通。", "講藝遵先𮜿，覩德暢宸衷。", "鷲嶺飛夏服，娥魄亂雕弓。", "汗浹鑣流赭，塵生埓散紅。", "飲羽驚開石，中葉遽凋叢。", "雁殫雲路靜，烏墜日輪空。", "九流參廣宴，萬宇抃恩隆。"]'),
('1ced6745-f334-45de-b6bc-b169f3bc3d60','奉和守歲應制','許敬宗','唐','唐诗','tang','','[]','玉琯移玄序，金奏賞彤闈。',60,'全唐诗/poet.tang.48000.json','["玉琯移玄序，金奏賞彤闈。", "祥鸞歌裏轉，春燕舞前歸。", "壽爵傳三禮，燈枝麗九微。", "運廣薰風積，恩深湛露晞。", "送寒終此夜，延宴待晨暉。"]'),
('fe904573-3cd1-452e-9bcf-e17e51f149f4','凌晨','盧照隣','唐','唐诗','tang','','[]','日掩鴻都夕，河低亂箭移。',48,'全唐诗/poet.tang.48000.json','["日掩鴻都夕，河低亂箭移。", "蟲飛明月戶，鵲繞落花枝。", "蘭襟帳北壑，玉匣鼓文漪。", "聞有啼鶯處，暗幄曉雲披。"]'),
('0b9eb36c-10cc-44f0-b1ff-0f13af8cde3c','登北固山','宋之問','唐','唐诗','tang','','[]','京鎮周天險，東南作北關。',48,'全唐诗/poet.tang.48000.json','["京鎮周天險，東南作北關。", "埭橫江曲路，戍入海中山。", "望越心初切，思秦鬢已斑。", "空憐上林雁，朝夕待春還。"]'),
('1f44e02b-2e60-43e3-bbb5-7443e9f28ffa','陪羣公登箕山賦得羣字','宋之問','唐','唐诗','tang','','[]','許由去已遠，冥莫見幽墳。',60,'全唐诗/poet.tang.48000.json','["許由去已遠，冥莫見幽墳。", "世薄人不貴，茲山唯白雲。", "寧知三千歲，復有堯爲君。", "時佐激頹俗，登箕挹清芬。", "高節雖旦暮，邈與洪崖羣。"]'),
('fce924e5-d51e-463c-97dc-d366989542f6','人日兼立春小園宴','蘇頲','唐','唐诗','tang','','["\u9ec4\u5c71"]','黃山積高次，表裏望京邑。',72,'全唐诗/poet.tang.48000.json','["黃山積高次，表裏望京邑。", "白日最靈朝，登攀盡原隰。", "年灰律象動，陽氣開迎入。", "煙靄長薄含，臨流小溪澀。", "賓朋莫我棄，詞賦當春立。", "更與韶物期，不孤東園集。"]'),
('9d619eca-11cc-4f3b-8cff-fab2c6e01389','和黃門舅十五夜作','蘇頲','唐','唐诗','tang','','[]','聞君陌上來，歌管沸相催。',48,'全唐诗/poet.tang.48000.json','["聞君陌上來，歌管沸相催。", "孤月連明照，千燈合暗開。", "寶裝遊騎出，香繞看車迴。", "獨有歸閑意，春庭伴落梅。"]'),
('c865f894-816c-46a9-bbc6-aeb0f18ee740','登綿州富樂山別李道士䇿','薛曜','唐','唐诗','tang','','[]','珠闕崑山遠，銀宮漲海懸。',48,'全唐诗/poet.tang.48000.json','["珠闕崑山遠，銀宮漲海懸。", "送君從此路，城郭幾千年。", "雲霧含丹景，桑麻覆細田。", "笙歌未盡曲，風馭獨泠然。"]'),
('4e0fb2b1-7fe9-4298-b12e-bd8a2b6965f7','九城尋山水','薛曜','唐','唐诗','tang','','[]','菊浦桃源瞰九城，鸞歌鳳嘯忽將迎。',64,'全唐诗/poet.tang.48000.json','["菊浦桃源瞰九城，鸞歌鳳嘯忽將迎。", "千巖雜樹雲霞色，百道流泉風雨聲。", "上客由來軒蓋重，幽人自覺薜蘿輕。", "疑是昔年棲息地，山中日暮有餘情。"]'),
('37d299b7-066f-400f-862a-871cd02f7f2f','邙山古意','薛曜','唐','唐诗','tang','','[]','昔掩佳城路，曾驚壑易遷。',96,'全唐诗/poet.tang.48000.json','["昔掩佳城路，曾驚壑易遷。", "今接宜都里，翻疑海作田。", "鏤鼎名應大，生金字不傳。", "風飆吹白日，羅綺拭黃泉。", "象鳳笙留國，成龍劒上天。", "長樂移新壟，咸陽失舊阡。", "川流徒漫漫，神理竟綿綿。", "佇見飛來鶴，沈嗟不學仙。"]'),
('5312e844-d52a-496f-a44d-0347971845ab','鳳閣南廳槐樹半生死雖遇陽和終呈枯朽託根清禁頗覺非宜感物緣情率爾爲詠','李懷遠','唐','唐诗','tang','','[]','庭槐歲月深，半死尚抽心。',72,'全唐诗/poet.tang.48000.json','["庭槐歲月深，半死尚抽心。", "葉少寧障日，枝疎不礙禽。", "帷幄諒無取，棟梁非所在。", "媿在龍樓側，羞處鳳池陰。", "未能辭雨露，猶得款衣簪。", "惜悲生意盡，空餘古木吟。"]'),
('61d4a0be-449b-4f0d-bffc-4055825898ef','和九月九日登慈恩寺浮圖應制','趙彥伯','唐','唐诗','tang','','[]','出豫垂佳節，憑高陟梵宮。',48,'全唐诗/poet.tang.48000.json','["出豫垂佳節，憑高陟梵宮。", "皇心滿塵界，佛迹現虛空。", "日月宜長壽，天人得大通。", "喜聞題寶偈，受記莫由同。"]'),
('6a7ee87f-b579-4951-b826-e435d86fb9a6','秋夜巫山','喬備','唐','唐诗','tang','','[]','巫峽裴回雨，陽臺淡蕩雲。',48,'全唐诗/poet.tang.48000.json','["巫峽裴回雨，陽臺淡蕩雲。", "江山空窈窕，朝暮自紛氳。", "螢色寒秋露，猨啼清夜聞。", "誰憐夢魂遠，腸斷思紛紛。"]'),
('86b7f2d5-f8f3-4572-80d2-9c8aad1aacc2','晦日與盧舍人同詣補闕城南林園','孫逖','唐','唐诗','tang','','[]','芳年正月晦，假日早朝迴。',48,'全唐诗/poet.tang.48000.json','["芳年正月晦，假日早朝迴。", "欲盡三春賞，還欽二阮才。", "柳迎郊騎入，花近□庭開。", "宛是人寰外，真情寓物來。"]'),
('c9cd36e5-6105-4959-80e4-9803fc8dd99c','贈劉藍田','盧象','唐','唐诗','tang','','[]','籬中犬迎吠，出屋候柴扉。',48,'全唐诗/poet.tang.48000.json','["籬中犬迎吠，出屋候柴扉。", "歲晏輸井稅，山村人暮歸。", "晚田始家食，餘布成我衣。", "對此能無事，勞君問是非。"]'),
('81e1e37d-6979-497f-a527-9015b612182c','清明日青龍寺上方','劉長卿','唐','唐诗','tang','','[]','上方偏可適，季月況堪過。',48,'全唐诗/poet.tang.48000.json','["上方偏可適，季月況堪過。", "遠近人都至，東西山色多。", "夕陽留逕草，新葉變庭柯。", "已度清明節，春愁如客何。"]'),
('b8ba9d98-7fdd-42e5-9b93-a6c2e250a624','羽山','蕭頴士','唐','唐诗','tang','','[]','九山方蕩潏，三考佇良材。',36,'全唐诗/poet.tang.48000.json','["九山方蕩潏，三考佇良材。", "夏祖何屯圯，遷殛此山隈。", "空餘下泉客，誰復辨黃能。"]'),
('8ce07641-2975-4123-abe5-a5e2b2f6ccb0','遊馬耳山','蕭頴士','唐','唐诗','tang','','[]','茲山表東服，遠近瞻其名。',168,'全唐诗/poet.tang.48000.json','["茲山表東服，遠近瞻其名。", "合沓盡溟漲，渾渾連太清。", "我來疑初伏，幽路無炎精。", "流水出溪盡，覆蘿搖風輕。", "高深變氣候，俯仰暮天晴。", "入谷煙雨潤，登崖雲日明。", "乾坤正含養，種植總滋榮。", "草樹皆秀色，雛麋亂新聲。", "攀巖挹桂髓，洞穴拾瑤英。", "此地隱微逕，何人得長生。", "宿心尚葛許，彌願棲蓬瀛。", "太息宦名路，遲迴忠孝情。", "還丹昧遠術，養素慚幽貞。", "安得從此去，悠然昇玉京。"]'),
('88488c60-807a-4e14-be17-d9d66d1cb06c','□□□趙載同遊焦湖夜歸作','蕭頴士','唐','唐诗','tang','','[]','□□將澤國，淜騰迎淮甸。',192,'全唐诗/poet.tang.48000.json','["□□將澤國，淜騰迎淮甸。", "東江輸大江，別流從此縣。", "仙尉俯勝境，輕橈恣遊衍。", "自公暇有餘，微尚得所願。", "拈引間翰墨，風流盡歡宴。", "稍移井邑閑，始悅登眺便。", "遙岫逢應接，連塘乍迴轉。", "劃然氣象分，萬頃行可見。", "波中峰一點，雲際帆千片。", "浩歎無端涯，孰知蘊虛變。", "往遊信不厭，畢景方未還。", "蘭□煙靄裏，延緣蒲稗間。", "勢隨風潮遠，心與□□閑。", "迴見出浦月，雄光射東關。", "悠然蓬壺事，□□□衰顏。", "安得傲吏隱，彌年寓茲山。"]'),
('e41de81a-1060-4cf1-aa51-071011f32c5e','龍興觀金籙建醮','王翰','唐','唐诗','tang','','["\u6cf0\u5c71"]','泰山巖巖兮凌紫氛，中有羣仙兮乘白雲，陳金薦璧兮□□□。',27,'全唐诗/poet.tang.48000.json','["泰山巖巖兮凌紫氛，中有羣仙兮乘白雲，陳金薦璧兮□□□。"]'),
('91285ada-838b-4f3f-9a57-6e909cb6cb55','山中松','張鼎','唐','唐诗','tang','','[]','枝聳碧雲端，根侵蘚壁盤。',48,'全唐诗/poet.tang.48000.json','["枝聳碧雲端，根侵蘚壁盤。", "幾經良匠顧，猶作散材看。", "雪積花開少，風多子落乾。", "空存後凋色，歲晚出林巒。"]'),
('98b5f1ff-c232-4e1e-a7e9-def2f9c9297c','庭前晚花開','李白','唐','唐诗','tang','','[]','西王母桃種我家，三千陽春始一花。',32,'全唐诗/poet.tang.48000.json','["西王母桃種我家，三千陽春始一花。", "結實苦遲爲人笑，攀折唧唧長咨嗟。"]'),
('56170485-7791-4084-ae2b-5f4d7a611eed','漢州王大錄事宅作','杜甫','唐','唐诗','tang','','[]','南溪老病客，相見下肩輿。',48,'全唐诗/poet.tang.48000.json','["南溪老病客，相見下肩輿。", "近髮看烏帽，催蓴煮白魚。", "宅中平岸水，身外滿牀書。", "憶爾才名叔，含悽意有餘。"]'),
('3a51727c-7910-475c-bf99-bd15c38bfa87','田家作','皇甫冉','唐','唐诗','tang','','[]','臥見高原燒，閑尋空谷泉。',144,'全唐诗/poet.tang.48000.json','["臥見高原燒，閑尋空谷泉。", "土膏消臘後，麥隴發春前。", "藥驗桐君錄，心齊莊子篇。", "荒村三數處，衰柳百餘年。", "好就山僧去，時過野舍眠。", "汲流寧厭遠，卜地本求偏。", "向子諳樵路，陶家置黍田。", "雪峰明晚景，風雁急寒天。", "且復冠名鶡，寧知冕戴蟬。", "問津夫子倦，荷蓧丈人賢。", "顧物皆從爾，求心正儻然。", "稽康嬾慢性，祗自戀風煙。"]'),
('5dd0b43b-a677-4ee0-809d-f75aaf0cefa5','寄劉方平','皇甫冉','唐','唐诗','tang','','[]','十年不出蹊林中，一朝結束甘從戎。',144,'全唐诗/poet.tang.48000.json','["十年不出蹊林中，一朝結束甘從戎。", "嚴子持竿心寂歷，寥落荒籬遮舊宅。", "終日碧湍聲自喧，暮秋黃菊花誰摘。", "每望南峰如對君，昨來不見多黃雲。", "石徑幽人何所在，玉泉疎鐘時獨聞。", "與君從來同語默，豈是悠悠但相識。", "天畔三秋空復情，袖中一字無由得。", "世人易合復易離，故交棄置求新知。", "歎息青青長不改，歲寒霜雪貞松枝。"]'),
('92e5941a-9a07-40eb-8a49-9cc7a6c2ddf0','和中丞奉使承恩還終南舊居','皇甫冉','唐','唐诗','tang','','[]','軒車尋舊隱，賓從滿郊園。',72,'全唐诗/poet.tang.48000.json','["軒車尋舊隱，賓從滿郊園。", "蕭散煙霞興，殷勤故老言。", "謝公山不改，陶令菊猶存。", "苔蘚侵垂釣，松篁長閉門。", "風霜清吏事，江海諭君恩。", "祗召趨宣室，沈冥在一論。"]'),
('8895e9b0-8362-498a-b82f-5e1b6706678d','送令狐明府','皇甫冉','唐','唐诗','tang','','[]','行當臘候晚，共惜歲陰殘。',48,'全唐诗/poet.tang.48000.json','["行當臘候晚，共惜歲陰殘。", "聞道巴山遠，如何蜀路難。", "荒林藏積雪，亂石起驚湍。", "君有親人術，應令勞者安。"]'),
('c0b75ba8-5d13-4988-a731-e4d2f8affd65','同韓給事觀畢給事畫松石','皇甫冉','唐','唐诗','tang','','[]','海嶠微茫那得到，楚關迢遞心空憶。',160,'全唐诗/poet.tang.48000.json','["海嶠微茫那得到，楚關迢遞心空憶。", "夕郎善畫巖間松，遠意幽姿此何極。", "千條萬葉紛異狀，虎伏螭盤爭勁力。", "扶疎半映晚天青，凝澹全和曙雲黑。", "煙籠月照安可道，雨濕風吹未曾息。", "能將積雪辨晴光，每與連峰作寒色。", "龍樓不競繁花吐，騎省偏宜遙夜直。", "羅浮道士訪移來，少室山僧舊應識。", "掖垣深沈晝無事，終日亭亭在人側。", "古槐衰柳寧足論，還對罘罳列行植。"]'),
('06633922-9d92-40d7-8802-bf29afe46c6e','送從姪棲閑律師','皇甫冉','唐','唐诗','tang','','[]','能知出世法，詎有在家心。',48,'全唐诗/poet.tang.48000.json','["能知出世法，詎有在家心。", "南院開門送，東山策杖尋。", "經年期故里，及夏到空林。", "念遠長勞望，朝朝草色深。"]'),
('78b8801f-141c-4f3d-8ca2-ef73f8088cc6','舟中送李觀','皇甫冉','唐','唐诗','tang','','[]','江南近別亦依依，山晚川長客伴稀。',32,'全唐诗/poet.tang.48000.json','["江南近別亦依依，山晚川長客伴稀。", "獨坐相思計行日，出門臨水望君歸。"]'),
('5f3d1c62-0511-4fb2-b2db-d8c816082da1','勅移橘栽','張彪','唐','唐诗','tang','','[]','南橘北爲枳，古來豈虛言。',96,'全唐诗/poet.tang.48000.json','["南橘北爲枳，古來豈虛言。", "徙植期不變，陰陽感君恩。", "枝條皆宛然，本土封其根。", "及時望栽種，萬里繞花園。", "滋味豈聖心，實以憂黎元。", "暫勞致力重，永感貢獻煩。", "是嗟草木類，稟異於乾坤。", "願爲王母桃，千歲奉至尊。"]'),
('21f5e72d-0f4c-4f9d-9d79-b4419b8fdf10','晚霽登王六東閣','嚴維','唐','唐诗','tang','','[]','試上江樓望，初逢山雨晴。',48,'全唐诗/poet.tang.48000.json','["試上江樓望，初逢山雨晴。", "連空青嶂合，向晚白雲生。", "俊美要殊觀，蕭條見遠情。", "情來不可極，日暮水流清。"]'),
('7a9a8bdc-38df-45fe-a6ed-309d99e699d6','曲龍山歌 一','顧況','唐','唐诗','tang','','[]','曲龍丈人冠藕花，其顏色映光明砂。',128,'全唐诗/poet.tang.48000.json','["曲龍丈人冠藕花，其顏色映光明砂。", "玉繩金枝有通籍，五嶽三山如一家。", "遙指叢霄呇靈島，島中曄曄無凡草。", "九仙傲倪折五芝，翠鳳白麟回異道。", "石臺石鏡月長明，石洞石橋連上清。", "人間妻子見不識，拍雲揮手升天行。", "摩天截漢何瀟灑，四石五雲更上下。", "下方小兆更拜焉，願得騎雲作車馬。"]'),
('1fad7421-313b-4af2-9323-ef08948d6502','曲龍山歌 二','顧況','唐','唐诗','tang','','[]','子欲居九夷，乘桴浮於海，聖人之意有所在。',116,'全唐诗/poet.tang.48000.json','["子欲居九夷，乘桴浮於海，聖人之意有所在。", "曲龍何在在海中，石室玉堂窅玲瓏。", "其下琛怪之所產，其上靈棲復無限。", "無風浪頂高屋脊，有風天晴翻海眼。", "願逐剛風騎吏旋，起居按摩參寥天。", "鳳皇頰骨流珠佩，孔雀尾毛張翠蓋。", "下看人界等蟲沙，夜宿層城阿母家。"]'),
('ad82da16-d919-4156-b1a8-6fb5ef620ed7','柳宜城鵲巢歌','顧況','唐','唐诗','tang','','[]','相公宅前楊柳樹，野鵲飛來復飛去。',76,'全唐诗/poet.tang.48000.json','["相公宅前楊柳樹，野鵲飛來復飛去。", "東家斫樹枝，西家斫樹枝。", "東家西家斫樹枝，發遣野鵲巢何枝。", "相君處分留野鵲，一月生得三箇兒。", "相君長命復富貴，口舌貧窮徒爾爲。"]'),
('09f2823e-bb05-4fff-b29d-b4cf583b6d27','道該上人院石竹花歌','顧況','唐','唐诗','tang','','[]','道該房前石竹叢，深淺紫，深淺紅。',48,'全唐诗/poet.tang.48000.json','["道該房前石竹叢，深淺紫，深淺紅。", "嬋娟灼爍委清露，小枝小葉飄香風。", "上人心中如鏡中，永日垂簾觀色空。"]'),
('1e31b96f-b2bf-49f1-a392-aa816f710f91','九日','耿湋','唐','唐诗','tang','','[]','九日強游登藻井，髮稀那敢插茱萸。',48,'全唐诗/poet.tang.48000.json','["九日強游登藻井，髮稀那敢插茱萸。", "橫空過雨千峰出，大野新霜萬壑鋪。", "更望尊中菊花酒，殷勤能得幾回沽。"]'),
('4a9d2293-f954-46ff-a919-cbb1b3a347a0','青陽館望九子山','竇叔向','唐','唐诗','tang','','["\u4e5d\u534e\u5c71"]','蒼翠岧嶢上碧天，九峰遙落縣門前。',64,'全唐诗/poet.tang.48000.json','["蒼翠岧嶢上碧天，九峰遙落縣門前。", "毫芒映日千重樹，涓滴垂空萬丈泉。", "武帝南遊曾駐蹕，始皇東幸亦祈年。", "雲祠絕跡終難訪，唯有猨聲到客邊。"]'),
('338811f4-7f95-4dd0-a885-b5667ee79e21','青出藍','王季友','唐','唐诗','tang','','[]','芳藍滋匹帛，人力半天經。',48,'全唐诗/poet.tang.48000.json','["芳藍滋匹帛，人力半天經。", "浸潤加新氣，光輝勝本清。", "還同冰出水，不共草爲螢。", "翻覆衣襟上，偏知造化靈。"]'),
('3136916f-caa1-4c8b-85ea-261ee06380cb','皇帝移晦日爲中和節','王季友','唐','唐诗','tang','','[]','皇心不向晦，改節號中和。',72,'全唐诗/poet.tang.48000.json','["皇心不向晦，改節號中和。", "淑氣同風景，嘉名別詠歌。", "湔裙移舊俗，賜尺下新科。", "曆象千年正，酺醵四海多。", "花隨春令發，鴻度歲陽過。", "天地齊休慶，歡聲欲蕩波。"]'),
('16ff683c-ff71-4a7f-ad9e-7b3baf0e6ff4','送劉南史往杭州拜覲別駕叔','劉商','唐','唐诗','tang','','[]','兄弟飄零自長年，見君眉白轉相憐。',64,'全唐诗/poet.tang.48000.json','["兄弟飄零自長年，見君眉白轉相憐。", "清揚似玉須勤學，富貴由人不在天。", "萬里榛蕪迷舊國，兩河烽火復相連。", "林中若使題書信，但問漳濱訪客船。"]'),
('ce06145c-beac-4628-8569-dbf0c790d20b','和汴州令狐相公白菊','楊巨源','唐','唐诗','tang','','[]','兔園春欲盡，別有一叢芳。',96,'全唐诗/poet.tang.48000.json','["兔園春欲盡，別有一叢芳。", "直似窮陰雪，全輕向曉霜。", "凝暉侵桂魄，晶彩奪螢光。", "素萼迎風舞，銀房泫露香。", "水晶簾不隔，雲母扇韜鋩。", "紈袖呈瑤瑟，冰容啓玉堂。", "今來碧油下，知自白雲鄉。", "留此非吾土，須移鳳沼傍。"]'),
('b641d8d9-8a91-40a2-9819-8c9c3d9e97cf','贈陳判官求子花詩','楊巨源','唐','唐诗','tang','','[]','油地輕綃碧且紅，須憐纖手是良工。',64,'全唐诗/poet.tang.48000.json','["油地輕綃碧且紅，須憐纖手是良工。", "能生麗思千花外，善點穠姿五彩中。", "子細傳看臨霽景，殷勤持贈及春風。", "若將江上迎桃葉，一帖何妨錦繡同。"]'),
('19a3e13e-c52d-485a-b6b6-f9b41115c61b','同諸公過福先寺律院宣上人房','歐陽詹','唐','唐诗','tang','','[]','律座下朝講，晝門猶掩關。',72,'全唐诗/poet.tang.48000.json','["律座下朝講，晝門猶掩關。", "叨同靜者來，正值高雲閑。", "寂爾方丈內，瑩然虛白間。", "千燈智慧心，片玉清羸顏。", "松色落深井，竹陰寒小山。", "晤言流曦晚，惆悵歸人寰。"]'),
('ea55d569-22e0-4bc4-9bf5-7078c40e9b27','城西別元九','白居易','唐','唐诗','tang','','[]','城西三月三十日，別友辭春兩恨多。',32,'全唐诗/poet.tang.48000.json','["城西三月三十日，別友辭春兩恨多。", "帝里却歸猶寂寞，通州獨去又如何。"]'),
('a8eede14-f760-47b7-8db9-1b25cff61a5e','陳家紫藤花下贈周判官','白居易','唐','唐诗','tang','','[]','藤花無次第，萬朵一時開。',24,'全唐诗/poet.tang.48000.json','["藤花無次第，萬朵一時開。", "不是周從事，何人喚我來。"]'),
('191fd21a-4102-4432-8ac9-78a11aefa5a9','遊小洞庭','白居易','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','湖山上頭別有湖，芰荷香氣占仙都。',64,'全唐诗/poet.tang.48000.json','["湖山上頭別有湖，芰荷香氣占仙都。", "夜含星斗分乾象，曉映雷雲作畫圖。", "風動綠蘋天上浪，鳥棲寒照月中烏。", "若非神物多靈迹，爭得長年冬不枯。"]'),
('f5cda4df-3f0d-4e69-8db8-881d74542130','傷蔡處士','楊衡','唐','唐诗','tang','','[]','篋中遺草是琅玕，對此令人灑淚看。',64,'全唐诗/poet.tang.48000.json','["篋中遺草是琅玕，對此令人灑淚看。", "三逕尚疑行迹在，數螢猶自映書殘。", "晨光不借泉門曉，暝色空添隴樹寒。", "欲問皇天天更遠，有才無命說應難。"]'),
('be061687-a553-48a3-b405-fcbcf685271b','奉使過石門瀑布','丘丹','唐','唐诗','tang','','[]','溪上望懸泉，耿耿雲中見。',132,'全唐诗/poet.tang.48000.json','["溪上望懸泉，耿耿雲中見。", "披榛上巖巘，絕壁正東面。", "千仞瀉聯珠，一潭噴飛霰。", "嵯灇滿山響，坐覺炎氛變。", "照日類虹蜺，從風似綃練。", "靈奇既天造，惜處窮海甸。", "吾祖昔登臨，謝公亦遊衍。", "王程懼淹泊，下磴空延眷。", "千里雷尚聞，巒迴樹葱蒨。", "奔波恭賤役，探討媿前彥。", "永欲洗塵纓，終當愜茲願。"]'),
('fbbd77c2-3da9-451a-beef-7d1634974dc7','秋夕宿石門館','丘丹','唐','唐诗','tang','','[]','暝從石門宿，搖落四岩空。',48,'全唐诗/poet.tang.48000.json','["暝從石門宿，搖落四岩空。", "潭月漾山足，天河瀉澗中。", "杉松寒似雨，猨鳥夕驚風。", "獨臥不成寐，蒼然想謝公。"]'),
('39de9ced-7a5e-46a3-b398-ca200e2ce4a7','廬山瀑布','張碧','唐','唐诗','tang','','["\u5e90\u5c71"]','誰將織女機頭練，貼出青山碧雲面。',128,'全唐诗/poet.tang.48000.json','["誰將織女機頭練，貼出青山碧雲面。", "造化工夫不等閑，剪破澄江凝一片。", "怪來洞口流嗚咽，怕見三冬晝飛雪。", "石鏡無光相對愁，漫漫頂上沈秋月。", "爭得陽烏照山北，放出青天豁胸臆。", "黛花新染插天風，驀吐中心爛銀色。", "五月六月暑雲飛，閣門遠看澄心機。", "參差碎碧落巖畔，梅花亂擺當風散。"]'),
('1a3811d5-8923-4c7b-84b4-30e71f349d34','林書記薔薇','張碧','唐','唐诗','tang','','[]','東風折盡諸花卉，是箇亭臺冷如水。',144,'全唐诗/poet.tang.48000.json','["東風折盡諸花卉，是箇亭臺冷如水。", "黃鸝舌滑跳柳陰，教看薔薇吐金蘂。", "雙成湧出琉璃宮，天香闊罩紅熏籠。", "西施曉下吳王殿，亂拋嬌臉新勻濃。", "瑤姬學繡流蘇幔，綠夾殷紅垂錦段。", "炎洲吹落滿汀雲，阮瑀庭前裝一半。", "醉且書懷還復吟，蜀箋影裏霞光侵。", "秦娥晚憑欄干立，柔枝墜落青羅襟。", "殷勤無波綠池水，爲君作鏡開妝蘂。"]'),
('e57261cf-bfbb-4c00-ba23-e7d42e3fa0a8','荅友人新栽松','張碧','唐','唐诗','tang','','[]','石門新長青龍髯，虬身宛轉雲光粘。',112,'全唐诗/poet.tang.48000.json','["石門新長青龍髯，虬身宛轉雲光粘。", "聞君愛我幽崖前，十株五株寒霜天。", "越溪老僧頭削雪，曾云手植當庭月。", "三十年來遮火雲，涼風五月生空門。", "願君栽於清澗泉，貞姿莫迓夭桃妍。", "□□易開還易落，貞姿鬱鬱長依然。", "山童嬾上孤峰巔，當窗劃破屏風煙。"]'),
('2ba1bb3f-6c11-4fc9-9b98-b71ff3b160bb','金錢花 一','陳翥','唐','唐诗','tang','','[]','裊露牽風夾瘦莎，一星星火遍窠窠。',32,'全唐诗/poet.tang.48000.json','["裊露牽風夾瘦莎，一星星火遍窠窠。", "閑門永巷新秋裏，幸不傷廉莫怕多。"]'),
('976e872c-e05f-4cc7-ab77-45eca944bfde','金錢花 二','陳翥','唐','唐诗','tang','','[]','古蘚寒蕪讓品流，小齋多謝伴清幽。',32,'全唐诗/poet.tang.48000.json','["古蘚寒蕪讓品流，小齋多謝伴清幽。", "若教夷甫門前種，也是無多過一秋。"]'),
('c5ab4bad-45b5-43da-b72a-b5b44dbd5a4f','山居雨霽即事','長孫佐輔','唐','唐诗','tang','','[]','結茅蒼嶺下，自與喧卑隔。',144,'全唐诗/poet.tang.48000.json','["結茅蒼嶺下，自與喧卑隔。", "況值雷雨晴，郊原轉岑寂。", "出門看反照，繞屋殘溜滴。", "古路絕人行，荒陂響螻蟈。", "籬崩瓜豆蔓，圃壤牛羊跡。", "斷續古祠鴉，高低遠村笛。", "喜聞東臯潤，欲往未通屐。", "杖策試危橋，攀蘿瞰苔壁。", "隣翁夜相訪，緩酌聊跂石。", "新月出汙尊，浮雲在中舃。", "常隳腐儒操，謬習經邦畫。", "有待時未知，非關慕沮溺。"]'),
('c1feef8a-fe93-4834-b360-57350f629835','秋日登山','長孫佐輔','唐','唐诗','tang','','[]','逐勝不怯寒，秋山閑獨登。',48,'全唐诗/poet.tang.48000.json','["逐勝不怯寒，秋山閑獨登。", "依稀小徑通，深處逢來僧。", "側右擁寒溜，欹松懸古藤。", "明書問知友，興詠將誰能。"]'),
('3d1e429a-adbd-40c2-9986-0848c832d031','自京師將赴黔南','竇鞏','唐','唐诗','tang','','[]','風雨荆州二月天，問人須雇峽中船。',32,'全唐诗/poet.tang.48000.json','["風雨荆州二月天，問人須雇峽中船。", "西南一望雲和水，猶道黔南有四千。"]'),
('426bdd3c-ea91-4ae3-92e8-24e838c33691','中秋夜洞庭圓月','姚合','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','素月閑秋景，騷人汎洞庭。',72,'全唐诗/poet.tang.48000.json','["素月閑秋景，騷人汎洞庭。", "滄波正澄霽，涼葉未飄零。", "練彩凝葭菼，霜容靜杳冥。", "曉棲河畔鶴，宵映渚邊螢。", "圓彩含珠魄，微颷發桂馨。", "誰憐採蘋客，此夜宿孤汀。"]'),
('6ddaa601-365c-48e4-b0c0-170c7bbc57c4','濉陽行','李涉','唐','唐诗','tang','','[]','黃昏日暮驅羸馬，夜宿濉陽烽火下。',128,'全唐诗/poet.tang.48000.json','["黃昏日暮驅羸馬，夜宿濉陽烽火下。", "此地新經殺戮來，墟落無煙空碎瓦。", "層冰塞斷隋朝水，一道銀河貫千里。", "愁心翻覆夢難成，病僕呻吟呼不起。", "泗水三千招義軍，本是征戰邀殊勳。", "十年麾下蓄壯氣，一朝此地爲愁人。", "昨日太陽回照燭，轉見天心重含育。", "早晚東風的發生，古堤春草年年綠。"]'),
('a9843076-b322-477a-887b-8c3a71873c37','六歎 一','李涉','唐','唐诗','tang','','[]','蓬萊島邊採珠客，西望人寰星漢隔。',96,'全唐诗/poet.tang.48000.json','["蓬萊島邊採珠客，西望人寰星漢隔。", "千重疊浪聳雲高，萬里平沙連月白。", "海中洞穴尋難極，水底鮫人半相識。", "玄蚌初開影暫明，驪龍欲近威難逼。", "辛苦風濤白首期，得珠却恨求珠時。", "隋侯歿世幾千載，只今薄俗空嗤嗤。"]'),
('6eb655f9-6ca0-455c-bc57-691c78e1332f','六歎 二','李涉','唐','唐诗','tang','','[]','燕王愛賢築金臺，四方豪俊承風來。',80,'全唐诗/poet.tang.48000.json','["燕王愛賢築金臺，四方豪俊承風來。", "秦王燒書殺儒客，肘腋之中千里隔。", "去年八月幽幷道，昭王陵邊哭秋草。", "今年二月遊函關，秦家城外悲河山。", "河上山邊車馬路，殘日青煙五陵樹。"]'),
('5879ba8f-d2f0-42cd-8508-ef6cbc24311b','六歎 三','李涉','唐','唐诗','tang','','[]','關東病儒客梁城，五歲十回逢亂兵。',96,'全唐诗/poet.tang.48000.json','["關東病儒客梁城，五歲十回逢亂兵。", "燒人之家食人肉，狼虎熾心都未足。", "城裏愁雲不開城，城頭野草春還綠。", "五十餘年忠烈臣，臨難守節羞謀身。", "堂上英髦沈白刃，門前輿隸乘朱輪。", "千古傷心汴河水，陰天落日悲風起。"]'),
('f027cfa2-5835-4ab5-98f1-b4d851f4b0a3','却歸巴陵途中走筆寄唐知言','李涉','唐','唐诗','tang','','[]','去年臘月來夏口，黑風白浪打頭吼。',352,'全唐诗/poet.tang.48000.json','["去年臘月來夏口，黑風白浪打頭吼。", "櫓聲軋軋搖不前，看他撩亂張帆走。", "逾月始到鸚鵡洲，嗚嗚暮角喧城頭。", "逡巡未得見官長，夢寢但覺生愁憂。", "軍中賢倅李監察，人馬曉來兼手札。", "教令參謁禮數全，頭頭要處相稱掣。", "唐氏一門今五龍，聲華殷殷皆如鍾。", "就中十一最年少，別有俊氣橫心胸。", "巧綴五言才刮骨，却怕柱天身硉矹。", "後輩無勞續出頭，坳塘不合窺溟渤。", "君家三兄舊山侶，方寸久來常許與。", "不覺淹留兩月餘，風光漫爛生洲渚。", "宇文文學儒家子，竹繞書齋花映水。", "醉舞狂歌此地多，有時酩酊扶還起。", "猥蒙方伯憐飢貧，假名許得陪諸賓。", "酒家債負有填日，恣意頗敢排青緡。", "余瞿二家同愛客，園蔬任遣奴人摘。", "野狐泉頭銀葉方，一別十年今再覿。", "更有風流歙奴子，能將盤帕來欺爾。", "白馬青袍豁眼明，許他真是查郎髓。", "良會芳時難再來，隟光電影長相催。", "扁舟惆悵人南去，目斷江天凡幾回。"]'),
('df521da7-8c6f-463c-88d9-973270c6353b','山中五無奈何 一','李涉','唐','唐诗','tang','','[]','無奈落葉何，紛紛滿衰草。',36,'全唐诗/poet.tang.48000.json','["無奈落葉何，紛紛滿衰草。", "疾來無氣力，擁戶不能掃。", "欲訪雲外人，都迷上山道。"]'),
('17c029d2-2e54-4433-a2d9-ce5fe8a87a7c','山中五無奈何 二','李涉','唐','唐诗','tang','','[]','無奈澗水何，喧喧夜鳴石。',36,'全唐诗/poet.tang.48000.json','["無奈澗水何，喧喧夜鳴石。", "疎林透斜月，散亂金光滴。", "欲訪澗底人，路窮潭水碧。"]'),
('7815a25f-96b9-403f-9f3e-38158bbbfdc1','山中五無奈何 三','李涉','唐','唐诗','tang','','[]','無奈阿鼎何，嬌啼索梨栗。',36,'全唐诗/poet.tang.48000.json','["無奈阿鼎何，嬌啼索梨栗。", "柴門正風雨，千向千回出。", "欲識老病心，賴渠將過日。"]'),
('72851b59-aa82-4519-96c9-3ba147dbd8d7','山中五無奈何 四','李涉','唐','唐诗','tang','','[]','無奈梅花何，滿巖光似雪。',36,'全唐诗/poet.tang.48000.json','["無奈梅花何，滿巖光似雪。", "春風總未至，獨自驚時節。", "欲見惆悵心，又看花上月。"]'),
('b3871d1f-d55e-4ad4-a278-ce4cb435c853','江南雜題','張祜','唐','唐诗','tang','','[]','積潦池新漲，頹垣址舊高。',48,'全唐诗/poet.tang.48000.json','["積潦池新漲，頹垣址舊高。", "怒蛙橫飽腹，鬬雀墮輕毛。", "碧瘦三稜草，紅鮮百葉桃。", "幽棲日無事，痛飲讀離騷。"]'),
('34f33874-afc4-4647-85ee-644c4bcd1809','賦得福州白竹扇子','張祜','唐','唐诗','tang','','[]','金泥小扇謾多情，未勝南工巧織成。',64,'全唐诗/poet.tang.48000.json','["金泥小扇謾多情，未勝南工巧織成。", "藤縷雪光纏柄滑，篾鋪銀薄露花輕。", "清風坐向羅衫起，明月看從玉手生。", "猶賴早時君不棄，每憐初作合歡名。"]'),
('a225f6f9-4416-4f5f-bbab-4e3b3bdf2c35','潤州楊別駕宅送蔣侍御收兵歸揚州','張祜','唐','唐诗','tang','','[]','冷氣清金虎，兵威壯鐵冠。',48,'全唐诗/poet.tang.48000.json','["冷氣清金虎，兵威壯鐵冠。", "揚旌川色暗，吹角水風寒。", "人對輜軿醉，花垂睥睨殘。", "羨歸丞相閣，空望舊門闌。"]'),
('42aa12e8-bb08-4d56-8c92-74d0c6e2fed0','觀泗州李常侍打毬','張祜','唐','唐诗','tang','','[]','日出樹煙紅，開場畫鼓雄。',72,'全唐诗/poet.tang.48000.json','["日出樹煙紅，開場畫鼓雄。", "驟騎鞍上月，輕撥鐙前風。", "斗轉時乘勢，旁捎乍迸空。", "等來低背手，爭得旋分騣。", "遠射門斜入，深排馬迥通。", "遙知三殿下，長恨出征東。"]'),
('bbf21aaa-abd4-46c2-87ce-ae4d154a14bd','閑居','張祜','唐','唐诗','tang','','[]','僻巷新苔徧，空庭弱柳垂。',48,'全唐诗/poet.tang.48000.json','["僻巷新苔徧，空庭弱柳垂。", "井欄防穉子，盆水試鵝兒。", "喜客加籩食，邀僧長路棋。", "未能拋世事，除此更何爲。"]'),
('c9515433-e5f5-40a4-b067-478ffa3d581c','渡吳江','杜牧','唐','唐诗','tang','','[]','堠館人稀夜更長，姑蘇城遠樹蒼蒼。',64,'全唐诗/poet.tang.48000.json','["堠館人稀夜更長，姑蘇城遠樹蒼蒼。", "江湖潮落高樓迥，河漢秋歸廣殿涼。", "月轉碧梧移鵲影，露低紅草溼螢光。", "文園詩侶應多思，莫醉笙歌掩華堂。"]'),
('0acf4571-85be-4330-8ae5-666154f171de','元日觀朝','厲玄','唐','唐诗','tang','','[]','玉座臨新歲，朝盈萬國人。',48,'全唐诗/poet.tang.48000.json','["玉座臨新歲，朝盈萬國人。", "火連雙闕曉，仗列五門春。", "瑞雪銷鴛瓦，祥光在日輪。", "天顏不敢視，稱慶拜空頻。"]'),
('ceed3cc4-2014-4831-b1a8-009bee641541','六月','趙璜','唐','唐诗','tang','','[]','六月火雲散，蟬聲鳴樹梢。',48,'全唐诗/poet.tang.48000.json','["六月火雲散，蟬聲鳴樹梢。", "秋風豈便借，客思已蕭條。", "傾國三年別，煙霞一路遙。", "行人斷消息，更上灞陵橋。"]'),
('52c6d58e-c308-4415-9562-f5862d8fd132','樊川寒食','喻鳧','唐','唐诗','tang','','[]','新松□綠草，古柏翳黃沙。',48,'全唐诗/poet.tang.48000.json','["新松□綠草，古柏翳黃沙。", "珮珂客驚鳥，綺羅人間花。", "蹙塵南北馬，碾石去來車。", "川晚悲風動，墳前碎紙斜。"]'),
('ef9c3012-c29a-440e-86da-53512b41035d','芍藥','潘咸','唐','唐诗','tang','','[]','閑來竹亭賞，賞極蘂珠宮。',48,'全唐诗/poet.tang.48000.json','["閑來竹亭賞，賞極蘂珠宮。", "葉已盡餘翠，花纔半展紅。", "媚欺桃李色，香奪綺羅風。", "每到春殘日，芳華處處同。"]'),
('871a889d-60ab-41d7-a393-1dd5d3d92c61','晚步','劉得仁','唐','唐诗','tang','','[]','野步晚悠悠，山光澹早秋。',48,'全唐诗/poet.tang.48000.json','["野步晚悠悠，山光澹早秋。", "遠空淪日脚，多稼沒人頭。", "古木蟬齊噪，深塍水慢流。", "幽居迴不近，秋策却堪愁。"]'),
('ed434a12-f7ae-4e98-8a1d-6197cbff0204','村晚閑步','劉得仁','唐','唐诗','tang','','[]','緩步出居處，過原邊雁行。',48,'全唐诗/poet.tang.48000.json','["緩步出居處，過原邊雁行。", "夕陽投草木，遠水迎蒼茫。", "野寺同蟾宿，雲溪劚藥嘗。", "蕭條霜景暮，極目盡堪傷。"]'),
('c7222cde-b174-4c7d-b45a-3157bd43d4bb','冬日題興善寺崔律師院孤松','劉得仁','唐','唐诗','tang','','[]','爲此疎名路，頻來訪遠松。',48,'全唐诗/poet.tang.48000.json','["爲此疎名路，頻來訪遠松。", "孤標宜雪後，每見憶山中。", "靜影生幽蘚，寒聲入迥空。", "何年植茲地，曉夕動清風。"]'),
('4f3b603c-5416-4095-a464-b81dbe6afa90','題新栽小松','劉得仁','唐','唐诗','tang','','[]','滿庭蕭颯皆凡木，豈得颼飀似石溪。',64,'全唐诗/poet.tang.48000.json','["滿庭蕭颯皆凡木，豈得颼飀似石溪。", "雪夜枝柯疑畫出，月中長短共人齊。", "未知何日干天及，恐到秋來被鶴棲。", "却向舊山尋得處，白雲根蕟覓應迷。"]'),
('414acb18-ca29-4858-91d7-3ee57709aa6d','栽松','劉得仁','唐','唐诗','tang','','[]','翠色凜空庭，披衣獨繞行。',48,'全唐诗/poet.tang.48000.json','["翠色凜空庭，披衣獨繞行。", "取從山頂嶮，栽得道心生。", "未弱幽泉韻，焉論別木聲。", "霜天殘月在，轉影入池清。"]'),
('55d9235e-a7ee-466d-a351-1df8d2af5bcc','十日菊','薛瑩','唐','唐诗','tang','','[]','昨日尊前折，萬人酣曉香。',48,'全唐诗/poet.tang.48000.json','["昨日尊前折，萬人酣曉香。", "今朝籬下見，滿地委殘陽。", "得失片時痛，榮枯一歲傷。", "未將同腐草，猶更有重霜。"]'),
('d5c5919b-c47b-4045-a5bb-faaa5d368cb8','赴南巴留別蘇臺知己','賈島','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','人過梅嶺上，歲歲北風寒。',48,'全唐诗/poet.tang.48000.json','["人過梅嶺上，歲歲北風寒。", "落日孤舟去，青山萬里看。", "猿聲湘水靜，草色洞庭寬。", "已料生涯事，只應持釣竿。"]'),
('319f58b1-8749-45a0-bf09-e0def1bce6ec','紅薔薇','莊南傑','唐','唐诗','tang','','[]','九天碎霞明澤國，造化工夫潛翦刻。',64,'全唐诗/poet.tang.48000.json','["九天碎霞明澤國，造化工夫潛翦刻。", "翠葉長眉約細枝，殷紅短刺鉤春色。", "明日當樓晚香歇，金帶盤空已成結。", "謝豹聲催麥隴秋，熏風吹落猩猩血。"]'),
('35b27368-84fb-4ab6-8c8b-23077b7c59aa','曉歌','莊南傑','唐','唐诗','tang','','[]','鵾雞哭樹星河轉，海上金烏翅如電。',64,'全唐诗/poet.tang.48000.json','["鵾雞哭樹星河轉，海上金烏翅如電。", "嫦娥斂髮綰雲頭，玉女舒霞織天面。", "九土廚煙滿城邑，商洛隴頭車馬急。", "魏宮鐘動繡窗明，夢娥驚對殘燈立。"]'),
('3e17a022-2f81-4918-a659-07277e090239','春草歌','莊南傑','唐','唐诗','tang','','[]','漠漠緜緜幾多思，無言領得春風意。',64,'全唐诗/poet.tang.48000.json','["漠漠緜緜幾多思，無言領得春風意。", "花裁小錦繡晴空，葉抽碧簟鋪平地。", "含芳弔影爭芬敷，繞雲恨起山蘼蕪。", "離人不忍到此處，淚娥滴盡雙真珠。"]'),
('d4378eb3-eccc-4e4f-bd1a-ae62119da5b4','古松歌','莊南傑','唐','唐诗','tang','','[]','山上山下松，森沈翠蓋煙。',74,'全唐诗/poet.tang.48000.json','["山上山下松，森沈翠蓋煙。", "龜鱗犀甲鏁支體，泉聲雨脚洗春風。", "深碧麈尾埽冥濛，淺黃龍腹盤穹崇。", "拏天攫地數千尺，恐作雲雨歸維嵩。", "維嵩成大廈，莫遣邂逅逢樵者。"]'),
('9e8554f0-330f-4a2c-a64b-bac4936a7e05','蒲中霽後晚望','薛能','唐','唐诗','tang','','[]','河邊霽色無人見，身帶春風立岸頭。',32,'全唐诗/poet.tang.48000.json','["河邊霽色無人見，身帶春風立岸頭。", "濁水茫茫有何意，日斜還向古蒲州。"]'),
('6373fcab-44e0-4dc2-8827-c8b49a7d9eb4','龍門八韻','薛能','唐','唐诗','tang','','[]','河浸華夷闊，山橫宇宙雄。',96,'全唐诗/poet.tang.48000.json','["河浸華夷闊，山橫宇宙雄。", "高波萬丈瀉，夏禹幾年功。", "川迸晴明雨，林生旦暮風。", "人看飜進退，鳥性斷西東。", "氣逐雲歸海，聲驅石落空。", "近身毛乍豎，當面語難通。", "沸沫歸何處，盤渦傍此中。", "從來化鬐者，攀去路應同。"]'),
('8cc61f10-7ce7-4b69-9408-4b34d6d2ce1c','新雪','薛能','唐','唐诗','tang','','[]','細落麤和忽復繁，頓清朝市不聞喧。',64,'全唐诗/poet.tang.48000.json','["細落麤和忽復繁，頓清朝市不聞喧。", "天迷皓色風何亂，地溼春泥土半飜。", "香暖會中懷岳寺，樵鳴村外想家園。", "閑吟只愛煎茶澹，斡破平光向近軒。"]'),
('a513b19d-0c29-4963-91a4-cdde3b8f9a16','送判官赴京','薛能','唐','唐诗','tang','','[]','闕下情偏已絕稀，天涯身遠復相依。',64,'全唐诗/poet.tang.48000.json','["闕下情偏已絕稀，天涯身遠復相依。", "庭花每對從容落，夜燭多同笑語歸。", "君子是行應柏署，鄙人何望即柴扉。", "青雲若遇交親話，白璧無心待發揮。"]'),
('de221824-f2ff-4b9f-9f9c-5dd137682ff3','溪東岑望天都山','朱景玄','唐','唐诗','tang','','[]','目望浮山丘，梯雲上東岑。',96,'全唐诗/poet.tang.48000.json','["目望浮山丘，梯雲上東岑。", "羣峰爭入冥，巉巉生太陰。", "昔賢此升仙，結構窮聳深。", "未曉日先照，當晝色半沈。", "風泉雪霜飛，雲樹瓊玉林。", "大道非閉隔，無路不可尋。", "窺鏡澄夙慮，望壇起敬心。", "一從呼子安，永絕金玉音。"]'),
('82e53ca2-fe2a-4d96-8efe-9801c5ad8485','夜行次東關逢魏扶東歸','許渾','唐','唐诗','tang','','[]','南北斷蓬飄，長亭酒一瓢。',50,'全唐诗/poet.tang.48000.json','["南北斷蓬飄，長亭酒一瓢。", "殘雲歸太華，疏雨過中條。", "樹色隨關[迥]，河聲入塞遙。", "勞歌此分首，風急馬蕭蕭。"]'),
('a6520edd-a6b1-4431-a712-8528c1743907','南遊湘漢寄友人','李頻','唐','唐诗','tang','','[]','南去遠三京，三湘五月行。',48,'全唐诗/poet.tang.48000.json','["南去遠三京，三湘五月行。", "巴江雪水下，楚澤火雲生。", "向野聊中飲，乘涼探暮程。", "離懷不可說，已近峽猨聲。"]'),
('d6aa7dc7-141a-406a-ab6a-b54e9c38983d','送劉山人歸洞庭','李頻','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','却共孤雲去，高眠最上峰。',48,'全唐诗/poet.tang.48000.json','["却共孤雲去，高眠最上峰。", "半湖乘早月，中路入疏鐘。", "秋盡蟲聲急，夜深山雨重。", "當時同隱者，分得幾株松。"]'),
('35664761-ba2b-4683-a89b-776ab02faa29','早發','李郢','唐','唐诗','tang','','[]','野店星河在，行人道路長。',48,'全唐诗/poet.tang.48000.json','["野店星河在，行人道路長。", "孤燈憐宿處，斜月厭新裝。", "草色多寒露，蟲聲似故鄉。", "清秋無限恨，殘菊過重陽。"]'),
('dead5b8d-a26c-4913-95e5-a9e97f6e1086','題惠山','李郢','唐','唐诗','tang','','[]','乳洞陰陰碧澗連，杉松六月冷無蟬。',32,'全唐诗/poet.tang.48000.json','["乳洞陰陰碧澗連，杉松六月冷無蟬。", "黃昏飛盡白蝙蝠，茶火數星山寂然。"]'),
('dcb82ffb-1125-442a-8582-dff8dae03409','雨中看山榴落花','李郢','唐','唐诗','tang','','[]','山榴逼砌栽，山火一團開。',24,'全唐诗/poet.tang.48000.json','["山榴逼砌栽，山火一團開。", "盡日風兼雨，春渠擁作堆。"]'),
('02a8f0aa-bf46-4acc-9c4b-5a31d8bd814b','寄友人乞菊栽','李郢','唐','唐诗','tang','','[]','藥闌經雨正堪鋤，白菊煩君乞數株。',64,'全唐诗/poet.tang.48000.json','["藥闌經雨正堪鋤，白菊煩君乞數株。", "潘岳賦中芳思在，陶潛籬下綠英無。", "移來稍及蟬鳴樹，種罷長教酒滿壺。", "□子成仙縱難學，九秋思看集鳩雛。"]'),
('a7e95170-7f3c-40ee-bf95-5102640c9bce','江邊柳','李郢','唐','唐诗','tang','','[]','東風晴色挂闌干，眉葉初晴畏曉寒。',32,'全唐诗/poet.tang.48000.json','["東風晴色挂闌干，眉葉初晴畏曉寒。", "江上別筵終日有，綠條春在長應難。"]'),
('ac7a5fb5-609d-428f-9174-9637cf0d17ab','鵝兒','李郢','唐','唐诗','tang','','[]','臘後閑行村舍邊，黃鵝清水真可憐。',64,'全唐诗/poet.tang.48000.json','["臘後閑行村舍邊，黃鵝清水真可憐。", "何窮散亂隨新草，永日淹留在野田。", "無事羣鳴遮水際，爭來引頸逼人前。", "風吹楚澤蒹葭暮，看下寒溪逐去船。"]'),
('dd9961bd-d6d7-4cba-8638-a7edcab6e0c3','酬友人春暮寄枳花茶','李郢','唐','唐诗','tang','','[]','昨日東風吹枳花，酒醒春晚一甌茶。',64,'全唐诗/poet.tang.48000.json','["昨日東風吹枳花，酒醒春晚一甌茶。", "如雲正護幽人壍，似雪纔分野老家。", "金餅拍成和雨露，玉塵煎出照煙霞。", "相如病渴今全校，不羨生臺白頸鵶。"]'),
('acf5e605-5d9c-45af-a257-b7a25601b8a6','郢自街西醉歸馬鞭墜失崔員外起祕書知其闕用皆許見貽俄頃之間二信俱至短長堅重價不相饒輒抒短章仰酬珍錫','李郢','唐','唐诗','tang','','[]','蜀巖陰面冷冥冥，偃雪欺霜半露青。',64,'全唐诗/poet.tang.48000.json','["蜀巖陰面冷冥冥，偃雪欺霜半露青。", "銛刃翦裁多鵲媚，細鞘揮拂帶龍腥。", "崖垂萬仞知無影，蘚漬千年合有靈。", "蘭省貴寮蓬閣吏，一時緘贈到雲亭。"]'),
('e62e5fe8-0382-47a6-a291-0c56a1478ea1','即目','李郢','唐','唐诗','tang','','[]','自笑騰騰者，非憨又不狂。',96,'全唐诗/poet.tang.48000.json','["自笑騰騰者，非憨又不狂。", "何爲跧似鼠，而復怯於麞。", "落拓無生計，伶俜戀酒鄉。", "冥搜得詩窟，偶戰出文場。", "愛雪愁冬盡，懷人覺夜長。", "石樓多爽氣，檉案有餘香。", "運去非關拙，時來不在忙。", "平生兩閑暇，孤趣滿滄浪。"]'),
('20e8a1da-421b-43c5-90b3-18c33068a99d','羅敷東館亭下流泉云至前山擁咽經歲移時掬弄惆悵成章','李郢','唐','唐诗','tang','','[]','看山亭下小鳴泉，嗚咽難通亦可憐。',32,'全唐诗/poet.tang.48000.json','["看山亭下小鳴泉，嗚咽難通亦可憐。", "惆悵無人爲疎鑿，擁愁含恨過年年。"]'),
('44f774b5-c274-44b2-aaf9-d6c9ce935b08','白櫻樹','于武陵','唐','唐诗','tang','','[]','記得花開雪滿枝，和蠭和蝶帶花移。',32,'全唐诗/poet.tang.48000.json','["記得花開雪滿枝，和蠭和蝶帶花移。", "如今花落遊蠭去，空作主人惆悵詩。"]'),
('92ba21f6-3239-4371-99cb-6f1d8b48d042','過南城縣麻姑山 一','崔櫓','唐','唐诗','tang','','[]','似前如却玉堆堆，薄帶輕煙翠好裁。',64,'全唐诗/poet.tang.48000.json','["似前如却玉堆堆，薄帶輕煙翠好裁。", "斜倚兔鉤孤影伴，校低仙掌一頭來。", "盤疑虎伏形難寫，展認龍拏勢未迴。", "驚訝昔人曾羽化，此中爭不接瑤臺。"]'),
('ec08eaa0-9fa2-4b90-bbc6-a5ba88a33cc2','過南城縣麻姑山 二','崔櫓','唐','唐诗','tang','','[]','詩手難題畫手慙，淺青濃碧壘東南。',64,'全唐诗/poet.tang.48000.json','["詩手難題畫手慙，淺青濃碧壘東南。", "塵愁世界忙心在，霞伴神仙穩夢酣。", "雨涕自悲看雪鬢，星冠無計整雲篸。", "家風負荷須名宦，可惜千峰綠似藍。"]'),
('89f1a52a-4e3a-4b6a-b340-b493c463a174','過南城縣麻姑山 三','崔櫓','唐','唐诗','tang','','[]','差煙危碧半斜暉，何代仙人此羽飛。',64,'全唐诗/poet.tang.48000.json','["差煙危碧半斜暉，何代仙人此羽飛。", "高袖鎮長寒柏暗，古祠時復彩雲歸。", "紅塵鞭馬顏將換，碧落驂鸞意有違。", "聲利繫身家繫念，今生辜負六銖衣。"]'),
('ac93f193-f6ae-4d1d-abfc-6eb682bbc1e5','和友人題僧院薔薇花三首 一','崔櫓','唐','唐诗','tang','','[]','何人移得在蟬家，瑟瑟枝條簇簇霞。',64,'全唐诗/poet.tang.48000.json','["何人移得在蟬家，瑟瑟枝條簇簇霞。", "爭那寂寥埋草暗，不勝惆悵舞風斜。", "無緣影對金尊酒，可惜香和石鼎茶。", "看取老僧齊物意，一般拋擲等凡花。"]'),
('5483030a-9ba8-4922-a550-a84dd1efcf34','和友人題僧院薔薇花三首 二','崔櫓','唐','唐诗','tang','','[]','忍委芳心此地開，似霞顏色苦低迴。',64,'全唐诗/poet.tang.48000.json','["忍委芳心此地開，似霞顏色苦低迴。", "風驚少女偷香去，雨認巫娥覓伴來。", "今日獨憐僧院種，舊山曾映釣磯栽。", "三清上客知惆悵，勸我春醪一兩杯。"]'),
('fd3dce37-6ef3-4432-80c7-129285757f03','和友人題僧院薔薇花三首 三','崔櫓','唐','唐诗','tang','','[]','露香如醉態如慵，斜壓危闌草色中。',64,'全唐诗/poet.tang.48000.json','["露香如醉態如慵，斜壓危闌草色中。", "試問更誰過野寺，無憀徒自舞春風。", "蘭缸尚惜連明在，錦帳先愁入夏空。", "一日幾回來又去，不能容易捨深紅。"]'),
('9b4bb9b3-be96-457a-a165-7c9b6ecd8855','春晚泊船江村','崔櫓','唐','唐诗','tang','','[]','芳草青青古渡頭，漁家住處暫維舟。',64,'全唐诗/poet.tang.48000.json','["芳草青青古渡頭，漁家住處暫維舟。", "殘花半樹悄無語，細雨滿天風似愁。", "家信不來春又晚，客程難盡水空流。", "自憐愛失心期約，看取花時更遠遊。"]'),
('fd4e5787-2983-4015-ad8b-668a2840699f','柳','崔櫓','唐','唐诗','tang','','[]','風慢日遲遲，拖煙拂水時。',48,'全唐诗/poet.tang.48000.json','["風慢日遲遲，拖煙拂水時。", "惹將千萬恨，繫在短長枝。", "骨輭張郎瘦，腰輕楚女飢。", "故園歸未得，多少斷腸思。"]'),
('77ebfaf5-af98-45fb-8c55-e6bd1a67645e','蓮花','崔櫓','唐','唐诗','tang','','[]','影欹晴浪勢欹煙，恨態緘言日抵年。',64,'全唐诗/poet.tang.48000.json','["影欹晴浪勢欹煙，恨態緘言日抵年。", "輕霧曉和香積飯，片紅時墮化人船。", "人間有筆應難畫，雨後無塵更好憐。", "何限斷腸名不得，倚風嬌怯醉腰偏。"]'),
('12e67396-6714-4909-89a0-0624e8267ff5','殘蓮花 一','崔櫓','唐','唐诗','tang','','[]','倚風無力減香時，涵露如啼臥翠池。',32,'全唐诗/poet.tang.48000.json','["倚風無力減香時，涵露如啼臥翠池。", "金谷樓前馬嵬下，世間殊色一般悲。"]'),
('c515586f-9611-4066-ba6c-139fdbbdf18e','殘蓮花 二','崔櫓','唐','唐诗','tang','','[]','不耐高風怕冷煙，瘦紅欹委倒青蓮。',32,'全唐诗/poet.tang.48000.json','["不耐高風怕冷煙，瘦紅欹委倒青蓮。", "無人解把無塵袖，盛取殘香盡日憐。"]'),
('c2d21e07-2429-4977-aef6-3b2686ff2e0a','惜蓮花','崔櫓','唐','唐诗','tang','','[]','半塘前日染來紅，瘦盡金方昨夜風。',64,'全唐诗/poet.tang.48000.json','["半塘前日染來紅，瘦盡金方昨夜風。", "留樣最嗟無巧筆，護香誰爲惜熏籠。", "緣停翠櫂沈吟看，忍使良波積漸空。", "魂斷舊溪顦顇態，冷煙殘粉楚臺東。"]'),
('a33da766-052b-46a4-a11d-53f95c81313e','岳陽雲夢亭看蓮花','崔櫓','唐','唐诗','tang','','[]','似醉如慵一水心，斜陽欲暝彩雲深。',64,'全唐诗/poet.tang.48000.json','["似醉如慵一水心，斜陽欲暝彩雲深。", "清明月照羞無語，涼冷風吹勢不禁。", "曾向楚臺和雨看，只於吳苑弄船尋。", "當時爲汝題詩徧，此地依前泥苦吟。"]'),
('07b6f498-0173-43bf-af5a-1fcb4191d486','村路菊花','崔櫓','唐','唐诗','tang','','[]','褭風驚未定，溪影晚來寒。',48,'全唐诗/poet.tang.48000.json','["褭風驚未定，溪影晚來寒。", "不得重陽節，虛將滿把看。", "神仙誰采掇，煙雨惜彫殘。", "牧豎樵童看，應教愛爾難。"]'),
('d111d6f6-6e55-4b66-8755-a2325bacbcea','題山驛新桐花','崔櫓','唐','唐诗','tang','','[]','雨餘煙膩暖香浮，影暗斜陽古驛樓。',64,'全唐诗/poet.tang.48000.json','["雨餘煙膩暖香浮，影暗斜陽古驛樓。", "丹鳳總巢阿閣去，紫花空映楚雲愁。", "堪憐翠蓋奇於畫，更惜芳庭冷似秋。", "長日老春看落盡，野禽閑哢碧悠悠。"]'),
('e53fa388-3699-47c3-990c-c980650466f0','山路木芙蓉','崔櫓','唐','唐诗','tang','','[]','不向橫塘泥裏栽，兩株晴笑碧巖隈。',64,'全唐诗/poet.tang.48000.json','["不向橫塘泥裏栽，兩株晴笑碧巖隈。", "枉教絕世深紅色，只向深山僻處開。", "萬里王孫應有恨，三年賈傅惜無才。", "緣花更歎人間事，半日江邊悵望迴。"]'),
('a3882103-1dc2-47c8-8703-3fcedc34659c','新柳','崔櫓','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','無情柔態任春催，似不勝風倚古臺。',32,'全唐诗/poet.tang.48000.json','["無情柔態任春催，似不勝風倚古臺。", "多少去年今日恨，御溝顏色洞庭來。"]'),
('04feb050-cf39-4bd7-8adb-27234fe38924','臨川見新柳','崔櫓','唐','唐诗','tang','','[]','不見江頭三四日，橋邊楊柳老金絲。',64,'全唐诗/poet.tang.48000.json','["不見江頭三四日，橋邊楊柳老金絲。", "岸南岸北往來渡，帶雨帶煙深淺枝。", "何處故鄉牽夢想，兩迴他國見榮衰。", "汀州草色亦如此，愁殺遠人人不知。"]'),
('14e82926-a0b7-41aa-894a-d4fbb025f561','南陽見柳','崔櫓','唐','唐诗','tang','','[]','夜來風入最高枝，罥斷愁腸幾尺絲。',64,'全唐诗/poet.tang.48000.json','["夜來風入最高枝，罥斷愁腸幾尺絲。", "楚塞曾吟煙午處，曲江長憶雪晴時。", "金銜細轂縈迴岸，戍笛牛歌遠近陂。", "還把舊年惆悵意，武安城下一吟詩。"]'),
('5c6a476d-8adf-47ff-8925-90a07be79177','別君山','崔櫓','唐','唐诗','tang','','[]','點空誇黛妬愁媚，何必浮來結夢思。',32,'全唐诗/poet.tang.48000.json','["點空誇黛妬愁媚，何必浮來結夢思。", "慙媿二年青翠色，惹窗黏枕伴吟詩。"]'),
('1410c70b-634e-4b9f-9e52-ac3870992381','宿壽安山陰館聞泉','崔櫓','唐','唐诗','tang','','[]','一支清急萬山來，穿竹喧飛破石苔。',64,'全唐诗/poet.tang.48000.json','["一支清急萬山來，穿竹喧飛破石苔。", "夢在故鄉臨欲到，聲聞孤枕却驚迴。", "多愁鬢髮余甘老，有限年光爾莫催。", "綠憶舊遊相似處，月明山響子陵臺。"]'),
('199f8b8b-f1ba-49fb-816e-87e790a1c04a','共佳人守歲','劉綺莊','唐','唐诗','tang','','[]','桂華窮北陸，荆豔作東鄰。',48,'全唐诗/poet.tang.48000.json','["桂華窮北陸，荆豔作東鄰。", "殘妝欲送曉，薄衣已迎春。", "舉袖爭流雪，分歌競繞塵。", "不應將共醉，年去遠催人。"]'),
('1d617296-c22c-499c-8e6c-44862e5edd76','櫻桃花','皮日休','唐','唐诗','tang','','[]','婀娜枝香拂酒壺，向陽疑是不融酥。',32,'全唐诗/poet.tang.48000.json','["婀娜枝香拂酒壺，向陽疑是不融酥。", "晚來嵬峨渾如醉，惟有春風獨自扶。"]'),
('04b0309c-d99a-4c3e-bc80-b41123f04d23','夜看櫻桃花','皮日休','唐','唐诗','tang','','[]','纖枝瑤月弄圓霜，半入鄰家半入牆。',32,'全唐诗/poet.tang.48000.json','["纖枝瑤月弄圓霜，半入鄰家半入牆。", "劉阮不知人獨立，滿衣清露到明香。"]'),
('7900e2d7-9966-4992-a6df-8a12cd327788','詠白蓮 一','皮日休','唐','唐诗','tang','','[]','膩於瓊粉白於脂，京兆夫人未畫眉。',64,'全唐诗/poet.tang.48000.json','["膩於瓊粉白於脂，京兆夫人未畫眉。", "靜婉舞偷將動處，西施嚬效半開時。", "通宵帶露妝難洗，盡日凌波步不移。", "願作水仙無別意，年年圖與此花期。"]'),
('49fdebf2-d919-4606-b664-fae944e14dd0','詠白蓮 二','皮日休','唐','唐诗','tang','','[]','細嗅深看暗斷腸，從今無意愛紅芳。',64,'全唐诗/poet.tang.48000.json','["細嗅深看暗斷腸，從今無意愛紅芳。", "折來只合瓊爲客，把種應須玉甃塘。", "向日但疑酥滴水，含風渾訝雪生香。", "吳王臺下開多少，遙似西施上素妝。"]'),
('f57285b6-20aa-46df-bc85-509ccc81e436','赤門堰白蓮花','皮日休','唐','唐诗','tang','','[]','縞帶與綸巾，輕舟漾赤門。',48,'全唐诗/poet.tang.48000.json','["縞帶與綸巾，輕舟漾赤門。", "千迴紫萍岸，萬頃白蓮村。", "荷露傾衣袖，松風入髻根。", "瀟疎今若此，爭不盡餘尊。"]'),
('2a61a44d-3912-4d0c-b8d9-afbeacb7a2c1','丙午歲旦','司空圖','唐','唐诗','tang','','[]','雞報已判春，中年抱疾身。',48,'全唐诗/poet.tang.48000.json','["雞報已判春，中年抱疾身。", "曉催庭火暗，風帶寺幡新。", "多慮無成事，空休是吉人。", "梅花浮壽酒，莫笑又移巡。"]'),
('bae79b26-196f-4ebf-8892-4ff4ef069bf0','丁巳元日','司空圖','唐','唐诗','tang','','[]','稟朔華夷會，開春氣象生。',240,'全唐诗/poet.tang.48000.json','["稟朔華夷會，開春氣象生。", "日隨行闕近，嶽爲壽觴晴。", "作睿由稽古，昭仁事措刑。", "上玄勞眷佑，高廟保忠貞。", "星變當移幸，人心喜奉迎。", "傳呼清御道，雪涕識臣誠。", "鼎餁和方濟，台階潤欲平。", "扶天咨協力，併日召延英。", "金躍洪鑪動，雲驅衆蟄驚。", "關中留王氣，席上縱奇兵。", "累降搜賢詔，兼持進善旌。", "短轅收驥步，直路發鵬程。", "自乏匡時略，非沽矯俗名。", "鶴籠何足獻，蝸舍別無營。", "羸帶漳濱病，吟哀越客聲。", "移居荒藥圃，耗志在棋枰。", "醉忘身空老，書憐眼尚明。", "偶能甘蹇分，豈是薄浮榮。", "慮戒防微淺，□知近利輕。", "獻陵三百里，寤寐禱時清。"]'),
('88894dbf-89df-4172-b7b6-79bc6c2b7756','光啓三年人日逢鹿','司空圖','唐','唐诗','tang','','[]','浮世仍逢亂，安排賴佛書。',48,'全唐诗/poet.tang.48000.json','["浮世仍逢亂，安排賴佛書。", "勞生中壽少，抱疾上昇疎。", "日暖人逢鹿，園荒雪帶鋤。", "知非今又過，蘧瑗最憐渠。"]'),
('25413a3b-27ac-4baf-914f-110cff1ace46','浙上重陽','司空圖','唐','唐诗','tang','','[]','登高唯北望，菊助可□明。',48,'全唐诗/poet.tang.48000.json','["登高唯北望，菊助可□明。", "離恨初逢節，貧居只喜晴。", "好文時可見，學稼老無成。", "莫歎關山阻，何當不阻兵。"]'),
('b8a88928-484f-414b-b7f0-b7c2bbda2e54','乙巳歲愚春秋四十九辭疾拜章將免左掖重陽獨登上方','司空圖','唐','唐诗','tang','','[]','雪鬢不禁鑷，知非又此年。',48,'全唐诗/poet.tang.48000.json','["雪鬢不禁鑷，知非又此年。", "退居還有旨，榮路免妨賢。", "落落鳴蛩鳥，晴霞度雁天。", "自無佳節興，依舊菊籬邊。"]'),
('1fcf1733-df8d-44bd-a5c3-d7c8f683d8bb','重陽山居','司空圖','唐','唐诗','tang','','[]','此身逃難入鄉關，八度重陽在舊山。',64,'全唐诗/poet.tang.48000.json','["此身逃難入鄉關，八度重陽在舊山。", "籬菊亂來成爛熳，家僮常得解登攀。", "年隨曆日三分盡，醉伴浮生一片閑。", "滿目秋光還似鏡，殷勤爲我照衰顏。"]'),
('fbe1c25c-21a7-48aa-9154-69dd7dabd12b','旅中重陽','司空圖','唐','唐诗','tang','','[]','乘時爭路秪危身，經亂登高有幾人。',64,'全唐诗/poet.tang.48000.json','["乘時爭路秪危身，經亂登高有幾人。", "今歲節唯南至在，舊交墳向北邙新。", "當歌共惜初筵樂，且健無辭後會頻。", "莫道中冬猶有閏，蟾聲纔盡即青春。"]'),
('54f75c8d-93cf-45b8-9bd2-58f98af28d4a','南至日','司空圖','唐','唐诗','tang','','[]','年年山□□來頻，莫強孤危競要津。',64,'全唐诗/poet.tang.48000.json','["年年山□□來頻，莫強孤危競要津。", "吉卦偶成開病眼，暖簷還葺寄羸身。", "求仙自躁非無藥，報國當材別有人。", "鬢髮堪傷白已遍，鏡中更待白眉新。"]'),
('d9c043cb-25d3-457f-9d6e-2be124ef1343','五月九日','司空圖','唐','唐诗','tang','','[]','金石皆銷鑠，賢愚共網羅。',48,'全唐诗/poet.tang.48000.json','["金石皆銷鑠，賢愚共網羅。", "達從詩似偈，狂覺哭勝歌。", "高燕凌鴻鵠，枯槎壓芰荷。", "此中無別境，此外是閑魔。"]'),
('adfd7a71-262c-4bff-91e6-af8743221f7a','庚子臘月五日','司空圖','唐','唐诗','tang','','[]','複道朝延火，嚴城夜漲塵。',48,'全唐诗/poet.tang.48000.json','["複道朝延火，嚴城夜漲塵。", "驊騮思故第，鸚鵡失佳人。", "禁漏虛傳點，妖星不振辰。", "何當迴萬乘，重覩玉京春。"]'),
('91405a89-5ea6-477e-a7e1-2b4e9e73e24b','中元夜看月','羅隱','唐','唐诗','tang','','[]','朦朧南溟月，洶湧出雲濤。',48,'全唐诗/poet.tang.48000.json','["朦朧南溟月，洶湧出雲濤。", "下射長鯨眼，遙分玉兔毫。", "勢來牛斗動，路越宵冥高。", "竟夕瞻光影，昂頭把白醪。"]'),
('80619ed1-d661-4426-a948-60a609f09bdf','木蘭','唐彥謙','唐','唐诗','tang','','[]','衆花搖落正無憀，脉脉芳叢契後凋。',64,'全唐诗/poet.tang.48000.json','["衆花搖落正無憀，脉脉芳叢契後凋。", "舒卷綠苞臨小檻，剪裁檀的綴長條。", "獨當春盡情何限，尚有秋期別未遙。", "桃葉近來消息絕，見君長憶渡江橈。"]'),
('025bf33a-51b2-4cde-b715-3e4d5227148b','玉蘂','唐彥謙','唐','唐诗','tang','','[]','玉蘂兩高樹，相輝松桂旁。',48,'全唐诗/poet.tang.48000.json','["玉蘂兩高樹，相輝松桂旁。", "向來塵不雜，此夜月仍光。", "秀掩叢蘭色，豔吞穠李芳。", "世人嫌具美，何必更清香。"]'),
('3f3f3d29-1d7f-4ce9-958c-f9605074f241','蓮','唐彥謙','唐','唐诗','tang','','[]','新蓮映多浦，迢遞綠塘東。',48,'全唐诗/poet.tang.48000.json','["新蓮映多浦，迢遞綠塘東。", "靜影搖波日，寒香映水風。", "金塵飄落蘂，玉露洗殘紅。", "看著餘芳少，無人問的中。"]'),
('ac902494-d395-4db4-b7aa-c56c9a798176','望岳時賊據華夏','唐彥謙','唐','唐诗','tang','','[]','長路風埃隔楚氛，忽驚神岳映朝曛。',64,'全唐诗/poet.tang.48000.json','["長路風埃隔楚氛，忽驚神岳映朝曛。", "削成絕壁五千仞，高揖泥金七十君。", "祝史祕辭今莫睹，從臣嘉頌久無聞。", "幽人閑望封中地，好爲吾皇起白雲。"]'),
('2e93fb3e-f73e-4246-a816-676b2104a4d7','片石','唐彥謙','唐','唐诗','tang','','[]','小齋廬阜石，寄自沃洲僧。',48,'全唐诗/poet.tang.48000.json','["小齋廬阜石，寄自沃洲僧。", "山客勞攜笈，幽人自得朋。", "瘦雲低作段，野浪凍成雲。", "便可同清話，何須有物憑。"]'),
('1072facc-8762-4f5b-b251-97ac0ed97b97','柳','唐彥謙','唐','唐诗','tang','','[]','春風向楊柳，能事盡風流。',48,'全唐诗/poet.tang.48000.json','["春風向楊柳，能事盡風流。", "有意疑張緒，無情見莫愁。", "依然金谷在，寧免武昌偷。", "前路難回首，何須苦映樓。"]'),
('88b18923-dbcf-4ae0-9f7e-4e8e6cb447a9','垂柳','唐彥謙','唐','唐诗','tang','','[]','垂柳碧髯茸，樓昏帶雨容。',96,'全唐诗/poet.tang.48000.json','["垂柳碧髯茸，樓昏帶雨容。", "思量成晝夢，來去發春慵。", "梳洗憑張敞，乘騎笑稚恭。", "碧虛從轉笠，紅燭近高舂。", "怨臉明秋水，愁眉淡遠峰。", "小園花盡蝶，靜院酒醒蛩。", "舊作琴臺鳳，今爲藥店龍。", "寶奩拋擲久，一任景陽鐘。"]'),
('27568442-ae4b-48e0-85f5-76178c789d41','紫薇花','唐彥謙','唐','唐诗','tang','','[]','素秋寒露重，芳事固應稀。',124,'全唐诗/poet.tang.48000.json','["素秋寒露重，芳事固應稀。", "小檻臨清沼，高叢見紫薇。", "溫{麻/昷}終有思，暗淡豈無輝。", "見欲迷交甫，誰能狀宓妃。", "妝新猶倚鏡，步緩不勝衣。", "怳似新相得，倀如久未歸。", "又疑神女過，猶佩七香幃。", "還似星娥織，初臨五綵機。", "慶雲今已集，威鳳莫驚飛。", "綺筆題難盡，煩君白玉徽。"]'),
('07620551-b361-473b-8437-8263268d26af','望中條','唐彥謙','唐','唐诗','tang','','[]','虞鄉縣西郭，改觀揖中條。',48,'全唐诗/poet.tang.48000.json','["虞鄉縣西郭，改觀揖中條。", "第蓄終南小，交□□□遙。", "崦深應有寺，峰近恐通橋。", "爲語前村叟，他時寄採樵。"]'),
('178757c8-beed-4bb4-a25b-5fa981136791','蒙穀山','唐彥謙','唐','唐诗','tang','','[]','蒙穀山低碧海枯，仲君閑坐說麻姑。',64,'全唐诗/poet.tang.48000.json','["蒙穀山低碧海枯，仲君閑坐說麻姑。", "遙天鶴語知虛實，長夜神光竟有無。", "祕祝齋心開九轉，侍臣回首聽三呼。", "交朋漫信文成術，短燭瑤壇漏滿壺。"]'),
('40373389-a5f9-4980-b68e-9d67637bca03','菊','唐彥謙','唐','唐诗','tang','','[]','雪菊金英兩斷腸，蝶翎蜂鼻帶清香。',64,'全唐诗/poet.tang.48000.json','["雪菊金英兩斷腸，蝶翎蜂鼻帶清香。", "寒村宿霧臨幽徑，廢苑斜暉傍短牆。", "近取松筠爲伴侶，遠將桃李作參商。", "年來病肺疎杯酒，每憶龍山似故鄉。"]'),
('871b5fee-cdee-4f3f-9daa-10364b261d59','山中','方干','唐','唐诗','tang','','[]','愛山却把圖書賣，嗜酒空教僮僕賒。',96,'全唐诗/poet.tang.48000.json','["愛山却把圖書賣，嗜酒空教僮僕賒。", "秪向堦前便漁釣，那知枕上有雲霞。", "暗泉出石飛仍咽，小徑通橋直復斜。", "窗竹未抽今夏笋，庭梅曾試當年花。", "姓名未及陶弘景，髭鬢白於姜子牙。", "松月水煙千古在，未知終久屬誰家。"]'),
('0257e28b-b434-45e5-91e2-3903e6d9ef98','次韻和盧先輩避難寺居看牡丹','王駕','唐','唐诗','tang','','[]','亂後寄僧居，看花恨有餘。',48,'全唐诗/poet.tang.48000.json','["亂後寄僧居，看花恨有餘。", "香宜閑靜立，態似別離初。", "朵密紅相照，欄低畫不如。", "狂風任吹却，最共野人疎。"]'),
('d3357800-9021-4647-a0a0-98499a0ee3c5','春宮怨','杜荀鶴','唐','唐诗','tang','','["\u5bab\u6028", "\u6625\u5929", "\u5199\u666f", "\u5973\u5b50", "\u5510\u8bd7\u4e09\u767e\u9996", "\u4e94\u8a00\u5f8b\u8bd7"]','早被嬋娟誤，欲妝臨鏡慵。',48,'全唐诗/poet.tang.48000.json','["早被嬋娟誤，欲妝臨鏡慵。", "承恩不在貌，教妾若爲容。", "風暖鳥聲碎，日高花影重。", "年年越溪女，相憶採芙蓉。"]'),
('8e52c82b-81d5-466c-b839-2d958224db4b','晨興','翁承贊','唐','唐诗','tang','','[]','鼓絕天街冷霧收，曉來風景已堪愁。',64,'全唐诗/poet.tang.48000.json','["鼓絕天街冷霧收，曉來風景已堪愁。", "槐無顏色因經雨，菊有精神爲傍秋。", "自愛鮮飆生戶外，不教閑事住心頭。", "披襟徐步一蕭灑，吟繞盆池想狎鷗。"]'),
('2e799ab8-8e5f-4108-b14b-1fe6a8d29199','江上吟曉','王貞白','唐','唐诗','tang','','[]','一葉野人舟，長將載酒游。',48,'全唐诗/poet.tang.48000.json','["一葉野人舟，長將載酒游。", "夜來吟思苦，江上月華秋。", "曉露滿紅蓼，輕波颺白鷗。", "漁翁似有約，相伴釣中流。"]'),
('c0c2efec-e03e-4b50-9464-56fa4d1007f6','過商山','王貞白','唐','唐诗','tang','','[]','一宿白雲根，時經採麝村。',48,'全唐诗/poet.tang.48000.json','["一宿白雲根，時經採麝村。", "數峰雖似蜀，當晝不聞猨。", "馬立溪沙淺，人爭閣道喧。", "明朝棄襦罷，步步入金門。"]'),
('55a63627-887e-44ed-be31-9cd80a032980','泛鏡湖□□','王貞白','唐','唐诗','tang','','[]','我泛鏡湖日，未生千里蓴。',48,'全唐诗/poet.tang.48000.json','["我泛鏡湖日，未生千里蓴。", "時無賀賓客，誰識謫仙人。", "吟對四時雪，憶遊三島春。", "惡聞忘越事，洗耳大江濱。"]'),
('1896a1b0-46a8-4a13-b98f-312b4b6ab3a1','太湖石','王貞白','唐','唐诗','tang','','["\u592a\u6e56"]','誰憐孤峭質，移在太湖心。',48,'全唐诗/poet.tang.48000.json','["誰憐孤峭質，移在太湖心。", "出得風波外，任他池館深。", "不同花逞豔，多媿竹垂陰。", "一片至堅操，那憂歲月侵。"]'),
('dcd00f7f-4490-4824-b084-738fead5d453','依韻和幹公題庭中太湖石二首 一','王貞白','唐','唐诗','tang','','["\u592a\u6e56"]','山立秪盈尋，高奇藥圃陰。',48,'全唐诗/poet.tang.48000.json','["山立秪盈尋，高奇藥圃陰。", "風濤打欲醉，巖穴蟄方深。", "蘚點晴偏綠，蛩藏曉競吟。", "歲寒終不變，堪比古人心。"]'),
('c148b4a9-fe32-4013-9fd1-14bf8e2a9c17','依韻和幹公題庭中太湖石二首 二','王貞白','唐','唐诗','tang','','["\u592a\u6e56"]','徒勞水府尋，宛在玉堂陰。',48,'全唐诗/poet.tang.48000.json','["徒勞水府尋，宛在玉堂陰。", "蘭圃安雖窄，盆池映轉深。", "山僧來盡愛，詩客見先吟。", "若是買花者，年年不計心。"]'),
('9651e406-f65e-497f-8d43-bcac9256a7c8','書陶潛醉石','王貞白','唐','唐诗','tang','','[]','片石陶真性，非爲麴糵昏。',48,'全唐诗/poet.tang.48000.json','["片石陶真性，非爲麴糵昏。", "爭如累月醉，不笑獨醒人。", "積疊莓苔色，交加薜荔根。", "至今重九日，猶待白衣魂。"]'),
('fb49fe0d-4821-4c48-a141-d58c08cbfab0','看天王院牡丹','王貞白','唐','唐诗','tang','','[]','前年帝里探春時，寺寺名花我盡知。',32,'全唐诗/poet.tang.48000.json','["前年帝里探春時，寺寺名花我盡知。", "今日長安已灰燼，忍隨南國對芳枝。"]'),
('ad91ac6c-72ab-4499-afd3-9a0535d249a2','芍藥','王貞白','唐','唐诗','tang','','[]','芍藥承春寵，何曾羨牡丹。',48,'全唐诗/poet.tang.48000.json','["芍藥承春寵，何曾羨牡丹。", "麥秋能幾日，穀雨只微寒。", "妬態風頻起，嬌妝露欲殘。", "芙蓉浣紗伴，長恨隔波瀾。"]'),
('968a855c-69e4-4f7b-88b5-8f8615ac99ba','獨芙蓉','王貞白','唐','唐诗','tang','','[]','方塘清曉鏡，獨照玉容秋。',48,'全唐诗/poet.tang.48000.json','["方塘清曉鏡，獨照玉容秋。", "蠹芰不相採，歛蘋空自愁。", "日斜還顧影，風起強垂頭。", "芳意羨何物，雙雙鸂鶒游。"]'),
('f6f059a4-bbb7-4ade-a357-43f1b2115ac4','馮氏書齋小松二首 一','王貞白','唐','唐诗','tang','','[]','孤根生遠岳，移植翠枝添。',48,'全唐诗/poet.tang.48000.json','["孤根生遠岳，移植翠枝添。", "自秉雪霜操，任他蜂蝶嫌。", "微陰連迥竹，清韻入疎簾。", "聳勢即空碧，時人看莫厭。"]'),
('a2d5db22-28a2-4cce-997b-21327002f573','馮氏書齋小松二首 二','王貞白','唐','唐诗','tang','','[]','得地已經歲，清音晝夜聞。',48,'全唐诗/poet.tang.48000.json','["得地已經歲，清音晝夜聞。", "根涵舊山土，葉間近溪雲。", "野鶴望長遠，庭花笑不羣。", "須知搖落後，衆木始能分。"]'),
('fecbde8f-50e3-463c-9d91-d6d1ad5c6385','社日村居','張蠙','唐','唐诗','tang','','[]','鵝湖山下稻粱肥，㹠穽雞棲對掩扉。',32,'全唐诗/poet.tang.48000.json','["鵝湖山下稻粱肥，㹠穽雞棲對掩扉。", "桑柘影斜春社散，家家扶得醉人歸。"]'),
('a7792bce-f546-495b-95e7-65944f0fe279','八月十六夜月','盧延讓','唐','唐诗','tang','','[]','十六勝三五，中天照大荒。',48,'全唐诗/poet.tang.48000.json','["十六勝三五，中天照大荒。", "秪訛些子緣，應號沒多光。", "桂老猶全在，蟾深未煞忙。", "難期一年事，到曉泥詩章。"]'),
('f03fa4bb-c159-48c2-89cf-f1b232e688fa','冬除夜書情','盧延讓','唐','唐诗','tang','','[]','兀兀坐無味，思量誰與隣。',48,'全唐诗/poet.tang.48000.json','["兀兀坐無味，思量誰與隣。", "數星深夜火，一箇遠鄉人。", "雁翥天微雪，風號樹欲春。", "愁章自難過，不覺苦吟頻。"]'),
('9db0a533-e9f9-4381-8d27-436ae3d4c10f','觀新歲朝賀','盧延讓','唐','唐诗','tang','','[]','龍墀初立仗，鴛鷺列班行。',48,'全唐诗/poet.tang.48000.json','["龍墀初立仗，鴛鷺列班行。", "元日燕脂色，朝天樺燭香。", "表章堆玉案，繒帛滿牙牀。", "三百年如此，無因及我唐。"]'),
('34ccba4e-0409-4160-b4ed-69adeefd081c','中秋月','曹松','唐','唐诗','tang','','[]','九十日秋色，今秋已十分。',48,'全唐诗/poet.tang.48000.json','["九十日秋色，今秋已十分。", "孤光吞列宿，四面絕微雲。", "衆木排疎影，寒流疊細紋。", "遙遙望丹桂，心緒更紛紛。"]'),
('8aa527eb-6fdf-4c06-9118-4f50eab6cdd0','寄方干','曹松','唐','唐诗','tang','','[]','桐廬江水閑，終日對柴關。',48,'全唐诗/poet.tang.48000.json','["桐廬江水閑，終日對柴關。", "因想別離處，不知多少山。", "釣舟春岸闊，庭樹晚煙還。", "莫便求棲隱，桂枝堪恨顏。"]'),
('b6a1cfef-8699-4193-8dbf-f57d688dbd46','宿山寺','曹松','唐','唐诗','tang','','[]','溪山盡日行，方聽遠鐘聲。',48,'全唐诗/poet.tang.48000.json','["溪山盡日行，方聽遠鐘聲。", "入院逢僧定，登樓見月生。", "露垂羣木潤，泉落一巖清。", "此景關吾事，通宵寐不成。"]'),
('c9852e74-691d-4e2b-b767-2041ac73e722','冬日登江樓','曹松','唐','唐诗','tang','','[]','高樓臨古岸，野步晚來登。',48,'全唐诗/poet.tang.48000.json','["高樓臨古岸，野步晚來登。", "江水因寒落，山雲爲雪凝。", "遠村雖入望，危檻不堪凭。", "親老未歸去，鄉愁徒自興。"]'),
('af9c79ca-fdd7-402f-9c4a-7053969e2ed6','寄李處士','曹松','唐','唐诗','tang','','[]','僧話磻溪叟，平生重赤松。',72,'全唐诗/poet.tang.48000.json','["僧話磻溪叟，平生重赤松。", "夜堂悲蟋蟀，秋水老芙蓉。", "吟坐倦垂釣，閑行多倚筇。", "聞名來已久，未得一相逢。", "塔見移來影，鐘聞過去聲。", "一齋唯默坐，應笑我營營。"]'),
('e6166ade-91c8-4f2b-8d7f-907ded6c50ba','客中立春','曹松','唐','唐诗','tang','','[]','玉燭傳佳節，陽和應此辰。',48,'全唐诗/poet.tang.48000.json','["玉燭傳佳節，陽和應此辰。", "土牛呈歲稔，綵燕表年春。", "臘盡星回次，寒餘月建寅。", "梅花將柳色，偏思越鄉人。"]'),
('9dc752f9-1582-45e2-81c1-e4604250e09c','南塘暝興','曹松','唐','唐诗','tang','','[]','水色昏猶白，霞光暗漸無。',48,'全唐诗/poet.tang.48000.json','["水色昏猶白，霞光暗漸無。", "風荷搖破扇，波月動連珠。", "蟋蟀啼相應，鴛鴦宿不孤。", "小僮頻報夜，歸步尚踟躕。"]'),
('6e336564-b0c4-4df2-8ba9-efb897cf6d57','送鄭谷歸宜春','曹松','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','無成歸故國，上馬亦高歌。',48,'全唐诗/poet.tang.48000.json','["無成歸故國，上馬亦高歌。", "況是飛鳴後，殊爲喜慶多。", "暑消嵩岳雨，涼吹洞庭波。", "莫使閑吟去，須期接盛科。"]'),
('72072457-9ada-48c4-b9ff-071881f19d49','送曾德邁歸寧宜春','曹松','唐','唐诗','tang','','[]','湘東山川有清輝，袁水詞人得意歸。',64,'全唐诗/poet.tang.48000.json','["湘東山川有清輝，袁水詞人得意歸。", "幾府爭馳毛義檄，一鄉看侍老萊衣。", "筵開灞岸臨清淺，路去藍關入翠微。", "想到宜陽更無事，併將歡慶奉庭闈。"]'),
('db07af25-0475-4859-a002-586d17f54324','山泉','李洞','唐','唐诗','tang','','[]','半空飛下水，勢去響如雷。',72,'全唐诗/poet.tang.48000.json','["半空飛下水，勢去響如雷。", "靜徹啼猨寺，高凌坐客臺。", "耳同經劒閣，身若到天台。", "濺樹吹成凍，凌祠觸作灰。", "深中試楖栗，淺處落莓苔。", "半夜重城閉，潺湲枕上來。"]'),
('8846b596-a357-4c82-852d-330a21c43826','松','盧士衡','唐','唐诗','tang','','[]','雲外千尋好性靈，伴杉陪柏事孤貞。',64,'全唐诗/poet.tang.48000.json','["雲外千尋好性靈，伴杉陪柏事孤貞。", "招呼暑氣終無分，應和涼風別有聲。", "細雨灑時花旋落，道人食處葉重生。", "如逢郢匠垂搜採，爲棟爲梁力不輕。"]'),
('467b61ed-3ea1-4993-a1de-7a50605468e0','再遊紫陽洞重題小松','盧士衡','唐','唐诗','tang','','[]','仙家種此充朝食，葉葉枝枝造化力。',96,'全唐诗/poet.tang.48000.json','["仙家種此充朝食，葉葉枝枝造化力。", "去年見時似鶴高，今年蕭騷八九尺。", "不同矮檜終委地，定向晴空倚天碧。", "好期逸士統貞根，昂枝點破秋苔色。", "尋思凡眼重花開，寧知此木超塵埃。", "秪是十年五年間，堪作大廈之宏材。"]'),
('dc5df054-37f7-4394-b6bf-7f69ab0f4920','湘江曉望','熊皎','唐','唐诗','tang','','[]','笙歌歡罷散離筵，水色朦朧蘸宿煙。',64,'全唐诗/poet.tang.48000.json','["笙歌歡罷散離筵，水色朦朧蘸宿煙。", "山響疎鐘何處寺，火光收釣下灘船。", "微雲過島侵微月，古岸平江浸遠天。", "歸夢已闌風色動，孤帆仍要住無緣。"]'),
('a9266f86-f64d-4b61-b813-87501807f89d','早行','熊皎','唐','唐诗','tang','','[]','結束何妨早，將行四顧頻。',48,'全唐诗/poet.tang.48000.json','["結束何妨早，將行四顧頻。", "山前猶見月，陌上未逢人。", "遠樹動宿鳥，危橋怯病身。", "漸明恆自慰，應免復迷津。"]'),
('7e717bb6-ef42-4659-863c-ed1554bf3549','遊嵩山','熊皎','唐','唐诗','tang','','[]','獨背焦桐訪洞天，暫攀靈迹棄塵緣。',64,'全唐诗/poet.tang.48000.json','["獨背焦桐訪洞天，暫攀靈迹棄塵緣。", "深逢野草皆疑藥，靜見樵人恐是仙。", "翠木入雲空自老，古碑橫水莫知年。", "可憐幽景堪長往，一任人間歲月遷。"]'),
('f3ab710e-616e-4afc-bbf5-8073f973b396','九華望廬山','熊皎','唐','唐诗','tang','','["\u5e90\u5c71"]','九江山勢盡崢嶸，惟有匡廬最得名。',64,'全唐诗/poet.tang.48000.json','["九江山勢盡崢嶸，惟有匡廬最得名。", "萬疊影遮殘雪在，數峰嵐帶夕陽明。", "冷侵醉榻鋪秋色，高亞吟龍送水聲。", "只待丹霄酬志了，白雲深處是歸程。"]'),
('33f6e824-97dd-4fc1-a37d-1b48db29bda8','道傍松','熊皎','唐','唐诗','tang','','[]','偃蓋當衢莫記年，獨含蒼翠鶴應憐。',64,'全唐诗/poet.tang.48000.json','["偃蓋當衢莫記年，獨含蒼翠鶴應憐。", "垂陰獨向笙歌地，有韻自成風雨天。", "塵□路岐分夜月，燒侵根脚起殘煙。", "論功只合行人賞，銷得煩蒸古道邊。"]'),
('26a5d526-2353-4fc1-9a6d-83df7695debc','月中桂','熊皎','唐','唐诗','tang','','[]','斷破重輪種者誰，銀蟾何事便相隨。',64,'全唐诗/poet.tang.48000.json','["斷破重輪種者誰，銀蟾何事便相隨。", "莫言望夜無攀處，却是吟人有得時。", "孤影不凋清露滴，異香常在好風吹。", "幾回目斷雲霄外，未必姮娥惜一枝。"]'),
('3340b36f-7c4d-412e-a4c0-248cdf5c804d','湖上望廬山','孫魴','唐','唐诗','tang','','["\u5e90\u5c71"]','輟櫂南湖首重迴，笑青吟翠向崔嵬。',32,'全唐诗/poet.tang.48000.json','["輟櫂南湖首重迴，笑青吟翠向崔嵬。", "天應不許人全見，長把雲藏一半來。"]'),
('178e4bd1-f606-4904-965e-8fe4f2437350','題梅嶺泉','孫魴','唐','唐诗','tang','','[]','梅嶺舊聞傳，林亭勢峞然。',288,'全唐诗/poet.tang.48000.json','["梅嶺舊聞傳，林亭勢峞然。", "登臨真不易，幽勝恐無先。", "楚野平千里，吳江曲一邊。", "標形都大別，洞府豈知焉。", "飛閣橫空去，征帆落面前。", "南雄雉堞峻，北壯鳳臺連。", "爛熳三春媚，參差百卉妍。", "風桃諸處錦，洛竹半溪煙。", "燕入晴梁語，鶯從暖谷遷。", "石根朝靄碧，簾際晚霞鮮。", "逕柳行難約，庭莎醉好眠。", "清明時更異，造化意疑偏。", "不獨宜韶景，尤須看暑天。", "藥苗繁似結，蘿蔓猛如編。", "珠亞垂枝果，冰澄汲井泉。", "粉牆蜩蛻落，丹檻雀雛顛。", "炎氣微茫覺，清飆左右穿。", "雲峰從勃起，葵葉豈勞扇。", "又見秋天麗，渾將夏日懸。", "紅黰著霜樹，香老臥池邊。", "菱芡誰鋪繡，莓苔自學錢。", "暗蟲依砌響，明月逗簾圓。", "小砌滋新菊，高軒噪暮蟬。", "雨聲寒颯颯，雁影曉聯聯。"]'),
('080e1c3d-6f9b-4f0d-9153-913e3eecfc2b','廬山瀑布','孫魴','唐','唐诗','tang','','["\u5e90\u5c71"]','有山來便有，萬丈落雲端。',48,'全唐诗/poet.tang.48000.json','["有山來便有，萬丈落雲端。", "霧噴千巖濕，雷傾九夏寒。", "圖中僧寫去，湖上客迴看。", "却羨爲猨鶴，飛鳴近碧湍。"]'),
('cec4c388-69ef-4193-9022-8537890625d3','牡丹','孫魴','唐','唐诗','tang','','[]','意態天生異，轉看看轉新。',48,'全唐诗/poet.tang.48000.json','["意態天生異，轉看看轉新。", "百花休放豔，三月始爲春。", "蝶死難離檻，鶯狂不避人。", "其如豪貴地，清醒復何因。"]'),
('67db364d-d692-4936-94fe-36b9c2f5aee1','主人司空後亭牡丹','孫魴','唐','唐诗','tang','','[]','佳卉挺芳辰，夭容乃絕倫。',192,'全唐诗/poet.tang.48000.json','["佳卉挺芳辰，夭容乃絕倫。", "望開從隔歲，愁過即無春。", "體物真英氣，餘花似庶人。", "蜂攢知眷戀，鳥語亦殷勤。", "況在豪華地，寧同里巷塵。", "酷憐應喪德，多賞奈怡神。", "忌穢栽時土，嘗甜折處津。", "繞行那識倦，圍坐豈辭頻。", "入夢殊巫峽，臨池勝洛濱。", "樂喧絲雜竹，露漬卯連寅。", "飲興尤思滿，吟情自合新。", "怕風惟怯夜，憂雨不經旬。", "欄檻爲良援，亭臺是四鄰。", "雖非能伐性，爭免礙還淳。", "鬬豔何慚蜀，矜繁未讓秦。", "私心期一日，許近看逡巡。"]'),
('686a3a13-87f8-4c84-a44f-6b60a32630ff','看牡丹二首 一','孫魴','唐','唐诗','tang','','[]','莫將紅粉比穠華，紅粉那堪比此花。',64,'全唐诗/poet.tang.48000.json','["莫將紅粉比穠華，紅粉那堪比此花。", "隔院聞香誰不惜，出欄呈豔自應誇。", "北方有態須傾國，西子能言亦喪家。", "輸我一枝和曉露，真珠簾外向人斜。"]'),
('425cd6a2-01c4-46d1-a27c-fda39aaaaedc','看牡丹二首 二','孫魴','唐','唐诗','tang','','[]','看花長到牡丹月，萬事全忘自不知。',64,'全唐诗/poet.tang.48000.json','["看花長到牡丹月，萬事全忘自不知。", "風促乍開方可惜，雨淋將謝可堪悲。", "閑年對坐渾成偶，醉後拋眠恐負伊。", "也擬便休還改過，迢迢爭奈一年期。"]'),
('5999f252-921a-4ca5-b4d0-eaa26b2fadc9','題未開牡丹','孫魴','唐','唐诗','tang','','[]','青苞雖小葉雖疎，貴氣高情便有餘。',64,'全唐诗/poet.tang.48000.json','["青苞雖小葉雖疎，貴氣高情便有餘。", "渾未盛時猶若此，算應開日合何如。", "尋芳蝶已棲丹檻，襯落苔先染石渠。", "無限風光言不得，一心留在暮春初。"]'),
('83883150-06ec-451b-a7c4-e135f2de9b41','主人司空見和未開牡丹輙却奉和','孫魴','唐','唐诗','tang','','[]','把筆臨芳不自怡，首徵章句促妖期。',64,'全唐诗/poet.tang.48000.json','["把筆臨芳不自怡，首徵章句促妖期。", "已驚常調言多鄙，遽捧高吟媿可知。", "絕代貞名應愈重，千金方笑更難移。", "狂歌狂醉猶堪羨，大拙當時是老時。"]'),
('caa55241-a4fa-418e-875d-f2bec7e1a0be','又題牡丹上主人司空','孫魴','唐','唐诗','tang','','[]','一年芳勝一年芳，愛重賢侯意異常。',64,'全唐诗/poet.tang.48000.json','["一年芳勝一年芳，愛重賢侯意異常。", "手闢紅房看闊狹，自張青幄蓋馨香。", "白疑美玉無多潤，紫覺靈芝不是祥。", "秪恐夢徵他日去，又須疑向鳳池傍。"]'),
('cb6ff04c-8734-45f6-836f-313faf26ee7a','牡丹落後有作','孫魴','唐','唐诗','tang','','[]','未發先愁有一朝，如今零落更魂銷。',64,'全唐诗/poet.tang.48000.json','["未發先愁有一朝，如今零落更魂銷。", "青叢別後無多色，紅線穿來已半焦。", "蓄恨綺羅猶眷眷，薄情蜂蝶去飄飄。", "明年雖道還期在，爭奈憑欄乍寂寥。"]'),
('75f27f46-9bc8-4ac3-8d25-a03f4d20c580','柳絮詠','孫魴','唐','唐诗','tang','','[]','年年三月裏，隨處自悠揚。',48,'全唐诗/poet.tang.48000.json','["年年三月裏，隨處自悠揚。", "雨過渾疑盡，風來特地狂。", "入花蜂有礙，遮水燕無妨。", "苦是添離思，青門道路長。"]'),
('a556fd46-65c6-44b5-b189-9641bb118d69','甘露寺紫薇花','孫魴','唐','唐诗','tang','','[]','蜀葵鄙下兼全落，菡萏清高且未開。',96,'全唐诗/poet.tang.48000.json','["蜀葵鄙下兼全落，菡萏清高且未開。", "赫日迸光飛蝶去，紫薇擎豔出林來。", "聞香不稱從僧舍，見影尤思在酒杯。", "誰笑晚芳爲賤劣，便饒春麗已塵埃。", "牽吟過夏惟憂盡，立看移時亦忘迴。", "惆悵寓居無好地，嬾能分取一枝栽。"]'),
('be5ffbdc-cce9-4542-a5b5-3a2fbaab2722','芳草','孫魴','唐','唐诗','tang','','[]','何處不相見，煙苗捧露心。',48,'全唐诗/poet.tang.48000.json','["何處不相見，煙苗捧露心。", "萋萋綠遠水，苒苒在空林。", "野吹閑搖闊，遊人醉臥深。", "南朝古城裏，碑石又應沈。"]'),
('245b6fcc-34ac-4348-bc0b-69f2f5aeb4d6','春苔','孫魴','唐','唐诗','tang','','[]','底物最牽吟，秋苔獨自尋。',48,'全唐诗/poet.tang.48000.json','["底物最牽吟，秋苔獨自尋。", "何時連夜雨，疊翠滿松陰。", "湘岸荒祠靜，吳宮古砌深。", "侯門還可惜，長被馬蹄侵。"]'),
('670d3f86-09bf-4d30-9573-1e76f86adcd9','老松','孫魴','唐','唐诗','tang','','[]','鬱鬱復蒼蒼，秋風韻更長。',48,'全唐诗/poet.tang.48000.json','["鬱鬱復蒼蒼，秋風韻更長。", "空心應有□，老葉不知霜。", "子落生深澗，陰清背夕陽。", "如逢東岱雨，猶得覆秦王。"]'),
('5968f3f8-a27a-4b5e-98ac-43641a9bbd2b','柳 一','孫魴','唐','唐诗','tang','','[]','蘢葱二月初，青軟自相紆。',48,'全唐诗/poet.tang.48000.json','["蘢葱二月初，青軟自相紆。", "意態花猶少，風流木更無。", "影繁晴陌上，煙重古城隅。", "煬帝河聲裏，幾番榮又枯。"]'),
('21de5487-0944-4b47-b55c-363c57af140f','柳 二','孫魴','唐','唐诗','tang','','[]','數樹新栽在畫橋，春來猶自長長條。',32,'全唐诗/poet.tang.48000.json','["數樹新栽在畫橋，春來猶自長長條。", "東風多事剛牽引，已解纖纖學舞腰。"]'),
('21422f86-b930-40ba-ba61-ab298568838d','柳 三','孫魴','唐','唐诗','tang','','[]','金堤堤上一林煙，況近清明二月天。',32,'全唐诗/poet.tang.48000.json','["金堤堤上一林煙，況近清明二月天。", "別有數枝遙望見，畫橋南面拂鞦韆。"]'),
('afadd1a9-e0d3-49fd-9fda-04166558563b','柳 四','孫魴','唐','唐诗','tang','','[]','春物牽情不奈何，就中楊柳態難過。',32,'全唐诗/poet.tang.48000.json','["春物牽情不奈何，就中楊柳態難過。", "也知是處無花去，爭奈看時未覺多。"]'),
('212b7544-93bb-41ab-9aab-613523bbadf9','柳 五','孫魴','唐','唐诗','tang','','[]','小眉初展綠條稠，露壓煙濛不自由。',32,'全唐诗/poet.tang.48000.json','["小眉初展綠條稠，露壓煙濛不自由。", "莫是折來偏屬意，依稀相似是風流。"]'),
('721e7a46-1838-4854-8723-e90a329b352a','柳 六','孫魴','唐','唐诗','tang','','[]','九衢春霽濕雲凝，着地𣯶𣯶礙馬行。',32,'全唐诗/poet.tang.48000.json','["九衢春霽濕雲凝，着地𣯶𣯶礙馬行。", "擬折無端拋又戀，亂穿來去羨黃鶯。"]'),
('d2756fbe-a287-4119-8380-9f2b1faaf09d','柳 七','孫魴','唐','唐诗','tang','','[]','千樹陰陰蓋御溝，雪花金穗思悠悠。',32,'全唐诗/poet.tang.48000.json','["千樹陰陰蓋御溝，雪花金穗思悠悠。", "先朝事後應無也，惟是荒根逐碧流。"]'),
('17f502e6-30d2-44e0-88a4-2269be1a29fc','柳 八','孫魴','唐','唐诗','tang','','[]','搖蕩和風恃賴春，蘸流遮路逐年新。',32,'全唐诗/poet.tang.48000.json','["搖蕩和風恃賴春，蘸流遮路逐年新。", "顛狂絮落還堪恨，分外欺凌寂寞人。"]'),
('3d5afa1d-5a0d-48c6-a562-39d85d3ba230','柳 九','孫魴','唐','唐诗','tang','','[]','暖催春促吐芳芽，伴雨從風處處斜。',32,'全唐诗/poet.tang.48000.json','["暖催春促吐芳芽，伴雨從風處處斜。", "莫道玄功無定配，不然爭得見桃花。"]'),
('2e6fc875-7c4d-48cc-9f1e-aeee70102e91','柳 十','孫魴','唐','唐诗','tang','','[]','小池前後碧江濱，窣翠拋青爛熳春。',32,'全唐诗/poet.tang.48000.json','["小池前後碧江濱，窣翠拋青爛熳春。", "不是和風爲擡舉，可能開眼向行人。"]'),
('f547f640-78a7-4b87-8d8a-e7445d4a1941','柳 十一','孫魴','唐','唐诗','tang','','[]','深綠依依配淺黃，兩般顏色一般香。',32,'全唐诗/poet.tang.48000.json','["深綠依依配淺黃，兩般顏色一般香。", "到頭嬝娜成何事，秪解年年斷客腸。"]');
